// ─── HF-4: Raw view helpers ────────────────────────────────────────
function raw_mime_type(string $ext): string {
    $map = [
        'txt'  => 'text/plain; charset=utf-8',
        'log'  => 'text/plain; charset=utf-8',
        'ini'  => 'text/plain; charset=utf-8',
        'sh'   => 'text/plain; charset=utf-8',
        'yml'  => 'text/plain; charset=utf-8',
        'yaml' => 'text/plain; charset=utf-8',
        'py'   => 'text/plain; charset=utf-8',
        'md'   => 'text/plain; charset=utf-8',
        'json' => 'application/json; charset=utf-8',
        'csv'  => 'text/csv; charset=utf-8',
        'js'   => 'text/plain; charset=utf-8',
        'html' => 'text/html; charset=utf-8',
    ];
    return $map[strtolower($ext)] ?? '';
}

function raw_extension_allowed(string $filename): bool {
    $ext = strtolower(pathinfo($filename, PATHINFO_EXTENSION));
    return raw_mime_type($ext) !== '';
}

function raw_mint_token($pdo, string $fileOwner, string $filePath, string $fileType, ?int $fileSize): array {
    if (!in_array($fileType, ['user','public'], true)) {
        return ['ok' => false, 'reason' => 'invalid_type'];
    }
    if (!raw_extension_allowed($filePath)) {
        return ['ok' => false, 'reason' => 'extension_not_allowed'];
    }
    $token = '';
    for ($attempt = 0; $attempt < 5; $attempt++) {
        $candidate = bin2hex(random_bytes(16));
        $check = $pdo->prepare("SELECT id FROM raw_tokens WHERE token = ?");
        $check->execute([$candidate]);
        if (!$check->fetch()) { $token = $candidate; break; }
    }
    if ($token === '') return ['ok' => false, 'reason' => 'token_collision'];

    $st = $pdo->prepare("INSERT INTO raw_tokens
        (token, file_owner, file_path, file_type, file_size, created_by)
        VALUES (?, ?, ?, ?, ?, ?)");
    $st->execute([$token, $fileOwner, $filePath, $fileType, $fileSize, $_SESSION['user']]);
    return ['ok' => true, 'token' => $token];
}

function raw_consume_token($pdo, string $token): ?array {
    $ttl = (int)getSetting($pdo, 'raw_token_ttl_hours', 24);
    $upd = $pdo->prepare("UPDATE raw_tokens
        SET consumed_at = NOW(), consumer_ip = ?, consumer_ua = ?
        WHERE token = ?
          AND consumed_at IS NULL
          AND created_at > DATE_SUB(NOW(), INTERVAL ? HOUR)");
    $ip = $_SERVER['REMOTE_ADDR'] ?? '';
    $ua = mb_substr($_SERVER['HTTP_USER_AGENT'] ?? '', 0, 300);
    $upd->execute([$ip, $ua, $token, $ttl]);
    if ($upd->rowCount() === 0) return null;

    $sel = $pdo->prepare("SELECT * FROM raw_tokens WHERE token = ?");
    $sel->execute([$token]);
    return $sel->fetch(PDO::FETCH_ASSOC) ?: null;
}

function getClientIp(){return $_SERVER['REMOTE_ADDR']??'0.0.0.0';}

function generateShareToken(PDO $pdo, int $maxRetries = 5): string {
    $alphabet = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';
    for ($i = 0; $i < $maxRetries; $i++) {
        $token = '';
        $bytes = random_bytes(8);
        for ($j = 0; $j < 8; $j++) {
            $token .= $alphabet[ord($bytes[$j]) % 62];
        }
        $stmt = $pdo->prepare("SELECT 1 FROM share_links WHERE token = ? LIMIT 1");
        $stmt->execute([$token]);
        if (!$stmt->fetchColumn()) return $token;
    }
    throw new RuntimeException('Failed to generate unique share token');
}

function isShareLinkRateLimited(PDO $pdo, string $token, string $ip): bool {
    $stmt = $pdo->prepare(
        "SELECT COUNT(*) FROM share_link_attempts
         WHERE token = ? AND ip_address = ? AND succeeded = 0
         AND created_at > DATE_SUB(NOW(), INTERVAL 15 MINUTE)"
    );
    $stmt->execute([$token, $ip]);
    return (int)$stmt->fetchColumn() >= 5;
}

function logShareAttempt(PDO $pdo, string $token, string $ip, bool $succeeded): void {
    $stmt = $pdo->prepare("INSERT INTO share_link_attempts (token, ip_address, succeeded) VALUES (?, ?, ?)");
    $stmt->execute([$token, $ip, $succeeded ? 1 : 0]);
}

function cleanupExpiredOneTimeShares(PDO $pdo): void {
    try {
        $stmt = $pdo->prepare(
            "SELECT id, owner, file_name FROM share_links
             WHERE is_one_time = 1
               AND consumed_at IS NOT NULL
               AND consumed_at < DATE_SUB(NOW(), INTERVAL 10 MINUTE)
               AND revoked_at IS NULL
             LIMIT 50"
        );
        $stmt->execute();
        $rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
        foreach ($rows as $row) {
            $filePath = getUserUploadPath($row['owner']) . $row['file_name'];
            if (file_exists($filePath) && is_file($filePath)) {
                @unlink($filePath);
            }
            $upd = $pdo->prepare("UPDATE share_links SET revoked_at = NOW() WHERE id = ? AND revoked_at IS NULL");
            $upd->execute([$row['id']]);
            logActivity($pdo, $row['owner'], 'share_link_consumed', $row['file_name'], 'File auto-deleted after one-time view');
        }
    } catch (Exception $e) { /* non-fatal */ }
}

function getDanaFontFaceCss(): string {
    static $css = null;
    if ($css === null) {
        $css = <<<'CSS'
@font-face{font-family:'Dana';src:url('data:font/truetype;base64,') format('truetype');font-weight:normal;font-style:normal;}
CSS;
    }
    return $css;
}

function buildPublicBaseUrl(): string {
    $trustProxy = defined('TRUST_PROXY_HEADERS') && TRUST_PROXY_HEADERS;

    $isHttps = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off')
        || ($trustProxy && !empty($_SERVER['HTTP_X_FORWARDED_PROTO']) && strtolower($_SERVER['HTTP_X_FORWARDED_PROTO']) === 'https')
        || ($trustProxy && !empty($_SERVER['HTTP_X_FORWARDED_SSL']) && strtolower($_SERVER['HTTP_X_FORWARDED_SSL']) === 'on')
        || (!empty($_SERVER['SERVER_PORT']) && (int)$_SERVER['SERVER_PORT'] === 443);

    $scheme = $isHttps ? 'https' : 'http';

    $host = ($trustProxy && !empty($_SERVER['HTTP_X_FORWARDED_HOST']))
            ? trim(explode(',', $_SERVER['HTTP_X_FORWARDED_HOST'])[0])
            : ($_SERVER['HTTP_HOST'] ?? 'localhost');

    // Strip any header-injection / path-traversal attempts.
    $host = preg_replace('/[^a-zA-Z0-9\.\-:]/', '', $host);

    $dir = rtrim(dirname($_SERVER['REQUEST_URI'] ?? '/'), '/');
    if ($dir === '' || $dir === '.' || $dir === '\\') $dir = '';

    return $scheme . '://' . $host . $dir;
}

function buildShareUrl(string $token): string {
    return buildPublicBaseUrl() . '/?action=share_view&t=' . urlencode($token);
}

function generateShareAccessKey(string $token): string {
    // Tied to the day (UTC) so visitors must re-enter password after ~24h.
    $bucket = gmdate('Ymd');
    return substr(hash_hmac('sha256', $token . '|' . $bucket, APP_SECRET), 0, 32);
}

function verifyShareAccessKey(string $token, string $key): bool {
    if ($key === '' || strlen($key) !== 32) return false;
    // Accept today and yesterday's buckets to handle UTC midnight rollover.
    $today = generateShareAccessKey($token);
    $yesterdayBucket = gmdate('Ymd', time() - 86400);
    $yesterday = substr(hash_hmac('sha256', $token . '|' . $yesterdayBucket, APP_SECRET), 0, 32);
    return hash_equals($today, $key) || hash_equals($yesterday, $key);
}

function renderSharePageStyles(): string {
    return getDanaFontFaceCss() . "\n" . "
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: 'Dana', -apple-system, system-ui, Tahoma, sans-serif; background: #0a0e1a; color: #e2e8f0; min-height: 100vh; padding: 20px; line-height: 1.6; }
        .wrap { max-width: 720px; margin: 40px auto; }
        .card { background: #111827; border: 1px solid #1e293b; border-radius: 16px; padding: 28px; box-shadow: 0 10px 40px rgba(0,0,0,.3); }
        .file-icon { font-size: 4rem; text-align: center; margin-bottom: 16px; }
        .file-name { font-size: 1.1rem; font-weight: 600; text-align: center; margin-bottom: 8px; word-break: break-all; color: #f1f5f9; }
        .file-meta { text-align: center; color: #94a3b8; font-size: 0.9rem; margin-bottom: 24px; }
        .preview-box { background: #0a0e1a; border-radius: 12px; padding: 16px; margin-bottom: 20px; overflow: auto; border: 1px solid #1e293b; }
        .preview-box img { max-width: 100%; height: auto; display: block; margin: 0 auto; border-radius: 8px; }
        .preview-box video, .preview-box audio { width: 100%; display: block; border-radius: 8px; }
        .preview-box pre { white-space: pre-wrap; word-break: break-word; font-family: 'JetBrains Mono', 'Courier New', monospace; font-size: 0.88rem; color: #cbd5e1; line-height: 1.6; direction: ltr; text-align: left; }
        .download-btn { display: block; width: 100%; padding: 14px; background: #3b82f6; color: #fff; text-align: center; border-radius: 12px; text-decoration: none; font-weight: 600; font-size: 1rem; transition: background .15s; border: none; cursor: pointer; font-family: inherit; }
        .download-btn:hover { background: #2563eb; }
        .copy-btn { background: #1e293b; color: #cbd5e1; border: 1px solid #334155; padding: 6px 12px; border-radius: 6px; cursor: pointer; font-family: inherit; margin-bottom: 16px; font-size: 0.82rem; }
        .copy-btn:hover { background: #334155; }
        .one-time-warn { background: #422006; color: #fbbf24; padding: 10px 14px; border-radius: 8px; margin-bottom: 16px; font-size: 0.9rem; text-align: center; border: 1px solid rgba(251,191,36,.2); }
        .footer { text-align: center; margin-top: 24px; color: #64748b; font-size: 0.8rem; }
        .pw-icon { font-size: 3rem; text-align: center; margin-bottom: 16px; }
        .pw-title { font-size: 1.1rem; font-weight: 600; text-align: center; margin-bottom: 20px; color: #f1f5f9; }
        .pw-input { width: 100%; padding: 12px 14px; background: #0a0e1a; color: #e2e8f0; border: 1px solid #334155; border-radius: 10px; font-family: inherit; font-size: 0.95rem; margin-bottom: 14px; }
        .pw-input:focus { outline: none; border-color: #3b82f6; }
        .pw-error { background: rgba(239,68,68,.08); color: #fca5a5; padding: 10px 14px; border-radius: 8px; margin-bottom: 14px; font-size: 0.88rem; text-align: center; border: 1px solid rgba(239,68,68,.2); }
        .err-icon { font-size: 4rem; text-align: center; margin-bottom: 16px; color: #ef4444; }
        .err-msg { text-align: center; font-size: 1rem; color: #fca5a5; }
    ";
}

/**
 * Returns true when the caller asked for application/json (SPA fetch path).
 * Process handlers branch on this to emit JSON instead of 302 redirects so
 * the SPA can swap views without a full reload.
 */
function wants_json(): bool {
    $accept = $_SERVER['HTTP_ACCEPT'] ?? '';
    return stripos($accept, 'application/json') !== false;
}

function auth_json_err(string $error, array $extra = []): void {
    header('Content-Type: application/json');
    echo json_encode(array_merge(['ok' => false, 'error' => $error], $extra));
    exit;
}

function auth_json_ok(array $data = []): void {
    header('Content-Type: application/json');
    echo json_encode(array_merge(['ok' => true], $data));
    exit;
}

/**
 * Snapshot of the live verify-view state for the SPA. Returns null when
 * there is no pending verification for either flow.
 */
function spa_verify_snapshot(): ?array {
    if (!empty($_SESSION['pending_password_reset'])) {
        $p = $_SESSION['pending_password_reset'];
        return [
            'flow'        => 'reset',
            'token'       => $p['token'] ?? '',
            'user_email'  => $p['email'] ?? '',
            'expires_at'  => isset($p['expires_at']) ? strtotime($p['expires_at']) : null,
            'next_redirect' => '?action=auth_shell&view=newpass',
        ];
    }
    if (!empty($_SESSION['pending_registration'])) {
        $p = $_SESSION['pending_registration'];
        return [
            'flow'        => 'register',
            'token'       => $p['token'] ?? '',
            'user_email'  => $p['email'] ?? '',
            'expires_at'  => isset($p['expires_at']) ? strtotime($p['expires_at']) : null,
            'next_redirect' => '?action=dashboard',
        ];
    }
    return null;
}

