// ================================================================
// PASSKEY (WebAuthn) HELPERS
// ================================================================
function pk_b64d($s){
    return base64_decode(strtr($s,'-_','+/').str_repeat('=',(4-strlen($s)%4)%4));
}
function pk_b64e($s){
    return rtrim(strtr(base64_encode($s),'+/','-_'),'=');
}

function cbor_read(&$d,&$p){
    $b=ord($d[$p++]);$mt=$b>>5;$ai=$b&0x1f;
    if($ai<24)$n=$ai;
    elseif($ai===24)$n=ord($d[$p++]);
    elseif($ai===25){$n=unpack('n',substr($d,$p,2))[1];$p+=2;}
    elseif($ai===26){$n=unpack('N',substr($d,$p,4))[1];$p+=4;}
    elseif($ai===27){
        $hi=unpack('N',substr($d,$p,4))[1];$p+=4;
        $lo=unpack('N',substr($d,$p,4))[1];$p+=4;
        $n=($hi<<32)|$lo;
    }
    else $n=0;
    switch($mt){
        case 0:return $n;
        case 1:return -1-$n;
        case 2:$v=substr($d,$p,$n);$p+=$n;return $v;
        case 3:$v=substr($d,$p,$n);$p+=$n;return $v;
        case 4:
            $a=[];
            for($i=0;$i<$n;$i++)$a[]=cbor_read($d,$p);
            return $a;
        case 5:
            $m=[];
            for($i=0;$i<$n;$i++){$k=cbor_read($d,$p);$m[$k]=cbor_read($d,$p);}
            return $m;
        case 6:return cbor_read($d,$p);
        case 7:
            if($ai===20)return false;
            if($ai===21)return true;
            if($ai===22)return null;
            if($ai===25)$p+=2;
            elseif($ai===26)$p+=4;
            elseif($ai===27)$p+=8;
            return null;
    }
}

function pk_der_length($len){
    if($len<128)return chr($len);
    $b='';$l=$len;
    while($l>0){$b=chr($l&255).$b;$l>>=8;}
    return chr(0x80|strlen($b)).$b;
}

function pk_ec_pem($x,$y){
    // SubjectPublicKeyInfo for P-256 uncompressed public key
    // OIDs: ecPublicKey 1.2.840.10045.2.1 + prime256v1 1.2.840.10045.3.1.7
    $algId = pack('H*','3013060720148648ce3d020106082a8648ce3d030107');
    // Correct OID bytes:
    $oidEC    = pack('H*','06072a8648ce3d0201');
    $oidP256  = pack('H*','06082a8648ce3d030107');
    $algSeq   = "0".pk_der_length(strlen($oidEC)+strlen($oidP256)).$oidEC.$oidP256;
    $rawKey   = "\x04".$x.$y;
    $bitStr   = "\x03".pk_der_length(strlen($rawKey)+1)."\x00".$rawKey;
    $spki     = "0".pk_der_length(strlen($algSeq)+strlen($bitStr)).$algSeq.$bitStr;
    return "-----BEGIN PUBLIC KEY-----
".chunk_split(base64_encode($spki),64,"
")."-----END PUBLIC KEY-----
";
}

function pk_rsa_pem($nBytes,$eBytes){
    if(strlen($nBytes)&&(ord($nBytes[0])&128))$nBytes="\x00".$nBytes;
    if(strlen($eBytes)&&(ord($eBytes[0])&128))$eBytes="\x00".$eBytes;
    $nInt="\x02".pk_der_length(strlen($nBytes)).$nBytes;
    $eInt="\x02".pk_der_length(strlen($eBytes)).$eBytes;
    $seq ="0".pk_der_length(strlen($nInt)+strlen($eInt)).$nInt.$eInt;
    $bs  ="\x03".pk_der_length(strlen($seq)+1)."\x00".$seq;
    $oid =pack('H*','300d06092a864886f70d0101010500');
    $spki="0".pk_der_length(strlen($oid)+strlen($bs)).$oid.$bs;
    return "-----BEGIN PUBLIC KEY-----
".chunk_split(base64_encode($spki),64,"
")."-----END PUBLIC KEY-----
";
}

function pk_parse_authdata($raw){
    if(strlen($raw)<37)return null;
    $r=[
        'rpIdHash' =>substr($raw,0,32),
        'flags'    =>ord($raw[32]),
        'signCount'=>unpack('N',substr($raw,33,4))[1],
    ];
    $r['up']=($r['flags']&0x01)!==0;
    $r['uv']=($r['flags']&0x04)!==0;
    $r['at']=($r['flags']&0x40)!==0;
    if($r['at']&&strlen($raw)>55){
        $off=37;
        $r['aaguid']=substr($raw,$off,16);$off+=16;
        $cl=unpack('n',substr($raw,$off,2))[1];$off+=2;
        $r['credId']=substr($raw,$off,$cl);$off+=$cl;
        try{
            $cose=cbor_read($raw,$off);
            $kty=$cose[1]??0;
            if($kty===2&&isset($cose[-2],$cose[-3])&&strlen($cose[-2])===32&&strlen($cose[-3])===32){
                $r['pubKeyPem']=pk_ec_pem($cose[-2],$cose[-3]);
            }elseif($kty===3&&isset($cose[-1],$cose[-2])){
                $r['pubKeyPem']=pk_rsa_pem($cose[-1],$cose[-2]);
            }
        }catch(Exception $e){}
    }
    return $r;
}

function pk_verify($pem,$authData,$cdJson,$sig){
    $msg=$authData.hash('sha256',$cdJson,true);
    $pub=openssl_pkey_get_public($pem);
    if(!$pub)return false;
    return openssl_verify($msg,$sig,$pub,OPENSSL_ALGO_SHA256)===1;
}
function pk_rpid(){return preg_replace('/:\d+$/','',($_SERVER['HTTP_HOST']??'localhost'));}
function pk_origin(){
    $s=(!empty($_SERVER['HTTPS'])&&$_SERVER['HTTPS']!=='off')?'https':'http';
    return $s.'://'.($_SERVER['HTTP_HOST']??'localhost');
}


