<script>
(function(){
    var ERR_MESSAGES = {
        invalid: '⚠️ نام کاربری یا رمز عبور اشتباه است.',
        captcha_wrong: '⚠️ پاسخ کپچا اشتباه است.',
        invalid_email: '⚠️ فرمت ایمیل نامعتبر است.',
        invalid_username: '⚠️ نام کاربری معتبر نیست.',
        weak_password: '⚠️ رمز عبور باید حداقل ۸ کاراکتر و شامل حروف و اعداد باشد.',
        password_mismatch: '⚠️ تکرار رمز با رمز اصلی مطابقت ندارد.',
        username_taken: '⚠️ این نام کاربری قبلاً انتخاب شده است.',
        send_failed: '⚠️ ارسال ایمیل با مشکل مواجه شد.',
        cooldown: '⏳ کمی صبر کنید و دوباره تلاش کنید.',
        rate_limit: '⏳ کمی صبر کن — یک بررسی به‌تازگی اجرا شده است.',
        check_disabled: '⚠️ سامانهٔ دریافت ایمیل خاموش است.',
        email_quota: '⛔ تعداد درخواست‌ها برای این ایمیل پر شده است.',
        ip_quota: '⛔ تعداد درخواست‌ها از این IP پر شده است.',
        referral_required: '⚠️ کد معرف لازم است.',
        referral_invalid: '⚠️ کد معرف معتبر نیست.',
        referral_expired: '⚠️ کد معرف منقضی شده است.',
        referral_used: '⚠️ کد معرف قبلاً استفاده شده یا به سقف رسیده است.',
        registration_disabled: '⚠️ ثبت‌نام عمومی غیرفعال است.',
        no_session: '⚠️ نشست منقضی شد. لطفاً از ابتدا شروع کنید.',
        expired: '⏰ پنجرهٔ زمانی منقضی شد.'
    };

    var AuthSPA = {
        current: document.body.dataset.initialView || 'login',
        verify: {
            token:   <?= json_encode($verifyTokenJs) ?>,
            email:   <?= json_encode($verifyEmailJs) ?>,
            toAddr:  <?= json_encode($toAddr) ?>,
            expires: <?= (int)$verifyExpiresJs ?>,
            flow:    <?= json_encode($verifyFlowJs) ?>,
            next:    <?= json_encode($verifyNextJs) ?>
        },
        sections: function(){ return document.querySelectorAll('section[data-view]'); },
        sectionFor: function(view){ return document.querySelector('section[data-view="' + view + '"]'); },
        clearError: function(section){
            if (!section) return;
            var slot = section.querySelector('[data-err-slot]');
            if (slot) { slot.hidden = true; slot.textContent = ''; }
        },
        showError: function(section, err){
            if (!section) return;
            var slot = section.querySelector('[data-err-slot]');
            if (!slot) { alert(err); return; }
            slot.textContent = ERR_MESSAGES[err] || err;
            slot.hidden = false;
        },
        refreshCaptchas: function(section){
            section.querySelectorAll('[data-captcha-img]').forEach(function(img){
                img.src = '?action=captcha_image&v=' + Date.now();
            });
        },
        show: function(view, opts){
            opts = opts || {};
            var next = this.sectionFor(view);
            if (!next) return;
            if (this.current === view && !opts.force) return;

            var prev = this.current ? this.sectionFor(this.current) : null;
            var self = this;
            var doEnter = function(){
                next.classList.remove('is-hidden');
                next.classList.add('is-entering');
                // Force reflow so the entering state paints
                void next.offsetHeight;
                next.classList.remove('is-entering');
                self.refreshCaptchas(next);
                self.clearError(next);
            };

            if (prev && prev !== next) {
                prev.classList.add('is-leaving');
                setTimeout(function(){
                    prev.classList.remove('is-leaving');
                    prev.classList.add('is-hidden');
                    doEnter();
                }, 220);
            } else {
                doEnter();
            }

            this.current = view;
            if (!opts.fromPop) {
                var qs = new URLSearchParams(location.search);
                qs.set('action', 'auth_shell');
                qs.set('view', view);
                history.pushState({view: view}, '', '?' + qs.toString());
            }

            if (view === 'verify' && !this._verifyInit) this.initVerify();

            // Move focus to first input of new section (accessibility + UX)
            setTimeout(function(){
                var firstInput = next.querySelector('input:not([type=hidden]):not([disabled])');
                if (firstInput && view !== 'verify') firstInput.focus();
            }, 250);
        },
        applyVerify: function(data){
            if (!data) return;
            this.verify.token   = data.token       || this.verify.token;
            this.verify.email   = data.user_email  || this.verify.email;
            this.verify.expires = data.expires_at  || this.verify.expires;
            this.verify.flow    = data.flow        || this.verify.flow;
            this.verify.next    = data.next_redirect || this.verify.next;
            var codeEl = document.getElementById('vfCode');
            if (codeEl) codeEl.textContent = this.verify.token;
            var emailEl = document.getElementById('vfEmail');
            if (emailEl) emailEl.textContent = this.verify.email;
            var mailto = document.getElementById('vfMailto');
            if (mailto) mailto.href = 'mailto:' + encodeURIComponent(this.verify.toAddr) +
                '?subject=' + encodeURIComponent(this.verify.token);
            var redirInput = document.getElementById('vfCheckRedirect');
            if (redirInput) redirInput.value = this.verify.flow === 'reset' ? 'forgot_password_step2' : 'register_step2';
        },
        submit: async function(form){
            var section = form.closest('section[data-view]');
            this.clearError(section);
            var btn = form.querySelector('button[type="submit"]');
            if (btn) btn.disabled = true;
            try {
                var fd = new FormData(form);
                var r = await fetch(form.action, {
                    method: 'POST',
                    headers: {'Accept': 'application/json'},
                    body: fd,
                    credentials: 'same-origin'
                });
                var j;
                try { j = await r.json(); }
                catch (e) {
                    // Server didn't return JSON — fall back to native submission
                    form.removeAttribute('data-spa-form');
                    form.submit();
                    return;
                }
                if (j.ok) {
                    if (j.verify) this.applyVerify(j.verify);
                    if (j.next_view) this.show(j.next_view);
                    else if (j.redirect) window.location = j.redirect;
                    else if (j.resent) this.flashOk(section, '✅ کد جدید صادر شد.');
                } else {
                    this.showError(section, j.error || 'send_failed');
                    this.refreshCaptchas(section);
                }
            } catch (e) {
                this.showError(section, 'send_failed');
            } finally {
                if (btn) btn.disabled = false;
            }
        },
        flashOk: function(section, msg){
            if (!section) return;
            var ok = section.querySelector('[data-ok-slot]');
            if (!ok) return;
            ok.textContent = msg;
            ok.hidden = false;
            setTimeout(function(){ ok.hidden = true; }, 2800);
        },
        _verifyInit: false,
        initVerify: function(){
            this.applyVerify({
                token: this.verify.token,
                user_email: this.verify.email,
                expires_at: this.verify.expires,
                flow: this.verify.flow,
                next_redirect: this.verify.next
            });
            if (this._verifyInit) return;
            this._verifyInit = true;
            this.startTimer();
            this.startPolling();
            this.bindCopyButtons();
        },
        startTimer: function(){
            var self = this;
            var totalSec = 10 * 60;
            (function tick(){
                var now = Math.floor(Date.now()/1000);
                var left = Math.max(0, (self.verify.expires || 0) - now);
                var tt = document.getElementById('vfTimerText');
                var tc = document.getElementById('vfTimerCircle');
                if (!tt) return;
                if (left <= 0) {
                    tt.textContent = 'منقضی';
                    tt.style.color = '#fca5a5';
                    if (tc) tc.style.strokeDashoffset = 264;
                    return;
                }
                var m = Math.floor(left/60), r = left%60;
                tt.textContent = m + ':' + (r<10?'0':'') + r;
                if (tc) tc.style.strokeDashoffset = (264 - 264 * (left / totalSec));
                setTimeout(tick, 1000);
            })();
        },
        startPolling: function(){
            var self = this;
            var line = document.getElementById('vfStatusLine');
            var spin = document.getElementById('vfStatusSpin');
            var txt  = document.getElementById('vfStatusText');
            var stopped = false;
            function setState(state, message){
                if (!line) return;
                line.classList.remove('ok','fail');
                if (state === 'ok') { line.classList.add('ok'); if (spin) spin.style.display='none'; }
                else if (state === 'fail') { line.classList.add('fail'); if (spin) spin.style.display='none'; }
                if (txt) txt.textContent = message;
            }
            async function poll(){
                if (stopped) return;
                try {
                    var r = await fetch('?action=inbound_status', {credentials:'same-origin', headers:{'Accept':'application/json'}});
                    var j = await r.json();
                    if (j.status === 'verified') {
                        stopped = true;
                        setState('ok', '✓ تایید شد — در حال انتقال...');
                        setTimeout(function(){
                            if (self.verify.flow === 'reset') self.show('newpass');
                            else window.location = j.redirect || self.verify.next || '?action=dashboard';
                        }, 700);
                        return;
                    }
                    if (j.status === 'expired') { stopped = true; setState('fail', '⏰ کد منقضی شد.'); return; }
                    if (j.status === 'race_error') { stopped = true; setState('fail', j.message || 'خطا در پردازش.'); return; }
                    if (j.status === 'no_session') { stopped = true; setState('fail', 'نشست منقضی شد.'); return; }
                    setTimeout(poll, 5000);
                } catch (e) { setTimeout(poll, 8000); }
            }
            poll();
        },
        bindCopyButtons: function(){
            document.querySelectorAll('section[data-view="verify"] .copy-btn, section[data-view="verify"] .copy-btn-wide').forEach(function(btn){
                btn.addEventListener('click', function(){
                    var t = document.getElementById(btn.getAttribute('data-target'));
                    if (!t) return;
                    var txt = t.textContent.trim();
                    var done = function(){
                        var o = btn.innerHTML;
                        btn.classList.add('copied');
                        btn.innerHTML = btn.classList.contains('copy-btn-wide') ? '✓ کپی شد' : '✓';
                        setTimeout(function(){ btn.classList.remove('copied'); btn.innerHTML = o; }, 1200);
                    };
                    if (navigator.clipboard && window.isSecureContext) navigator.clipboard.writeText(txt).then(done, done);
                    else { var ta = document.createElement('textarea'); ta.value = txt; ta.style.position='fixed'; ta.style.opacity=0;
                        document.body.appendChild(ta); ta.select(); try { document.execCommand('copy'); } catch(e){}
                        document.body.removeChild(ta); done(); }
                });
            });
        },
        runManualCheck: function(form){
            var btn = document.getElementById('vfCheckBtn');
            if (!btn || btn.disabled) return;
            var defaultSlot  = btn.querySelector('.check-btn-default');
            var loadingSlot  = btn.querySelector('.check-btn-loading');
            var cooldownSlot = btn.querySelector('.check-btn-cooldown');
            var cooldownNum  = document.getElementById('vfCooldownNum');
            var statusTxt    = document.getElementById('vfStatusText');
            var savedStatus  = statusTxt ? statusTxt.textContent : '';

            var MIN_LOADING_MS = 15000;
            var COOLDOWN_MS    = 15000;

            btn.disabled = true;
            defaultSlot.hidden = true; loadingSlot.hidden = false; cooldownSlot.hidden = true;

            var fetchPromise = fetch(form.action, {
                method: 'POST',
                credentials: 'same-origin',
                headers: {'Accept':'application/json','X-Requested-With':'fetch'},
                body: new FormData(form)
            }).then(function(r){ return r.json().catch(function(){ return {ok:false,error:'parse'}; }); })
              .catch(function(){ return {ok:false,error:'network'}; });

            var minDelay = new Promise(function(res){ setTimeout(res, MIN_LOADING_MS); });

            Promise.all([fetchPromise, minDelay]).then(function(arr){
                var j = arr[0];
                loadingSlot.hidden = true;

                if (j && j.ok && (j.matched|0) > 0) {
                    if (statusTxt) statusTxt.textContent = '✓ پیامت رسید — در حال انتقال...';
                    defaultSlot.hidden = true;
                    return;
                }

                if (statusTxt) {
                    statusTxt.textContent = j && j.error === 'rate_limit'
                        ? '⏳ کمی صبر کن — یک بررسی به‌تازگی اجرا شد'
                        : (j && j.ok ? '🔄 هنوز ایمیلی دریافت نشد — می‌توانی دوباره تلاش کنی' : '⚠️ خطا در بررسی — دوباره تلاش کن');
                }
                cooldownSlot.hidden = false;
                var leftSec = COOLDOWN_MS / 1000;
                if (cooldownNum) cooldownNum.textContent = leftSec;
                var timer = setInterval(function(){
                    leftSec -= 1;
                    if (leftSec <= 0) {
                        clearInterval(timer);
                        cooldownSlot.hidden = true;
                        defaultSlot.hidden = false;
                        btn.disabled = false;
                        if (statusTxt && statusTxt.textContent.indexOf('در حال انتظار') === -1) {
                            statusTxt.textContent = savedStatus || 'در حال انتظار برای پیامت...';
                        }
                    } else if (cooldownNum) {
                        cooldownNum.textContent = leftSec;
                    }
                }, 1000);
            });
        }
    };

    window.AuthSPA = AuthSPA;

    // Submit interception
    document.addEventListener('submit', function(e){
        var form = e.target;
        if (form.matches('[data-spa-form], [data-spa-form-resend]')) {
            e.preventDefault();
            AuthSPA.submit(form);
            return;
        }
        if (form.matches('[data-spa-form-check]')) {
            e.preventDefault();
            AuthSPA.runManualCheck(form);
            return;
        }
    });

    // SPA link navigation
    document.addEventListener('click', function(e){
        var a = e.target.closest('a[data-spa-link]');
        if (a) { e.preventDefault(); AuthSPA.show(a.dataset.spaLink); }
    });

    // Browser back/forward
    window.addEventListener('popstate', function(e){
        var v = (e.state && e.state.view) || (new URLSearchParams(location.search).get('view')) || 'login';
        AuthSPA.show(v, {fromPop: true});
    });

    // Set initial history state and init verify view if visible
    history.replaceState({view: AuthSPA.current}, '', '?action=auth_shell&view=' + AuthSPA.current);
    if (AuthSPA.current === 'verify') AuthSPA.initVerify();
})();

// ─── Passkey login (only shown on login view) ─────────────────────
(function(){
    function b64d(s){s=s.replace(/-/g,'+').replace(/_/g,'/');while(s.length%4)s+='=';var b=atob(s),a=new Uint8Array(b.length);for(var i=0;i<b.length;i++)a[i]=b.charCodeAt(i);return a.buffer;}
    function b64e(buf){var a=buf instanceof ArrayBuffer?new Uint8Array(buf):new Uint8Array(buf);return btoa(String.fromCharCode.apply(null,a)).replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');}
    function setSt(st, cls, txt){ if (!st) return; st.hidden = false; st.className = 'pk-status' + (cls?' '+cls:''); st.textContent = txt; }
    async function pkLogin(){
        var btn = document.getElementById('pkBtn');
        var st  = document.getElementById('pkSt');
        if (!window.PublicKeyCredential) { setSt(st,'e','مرورگر از Passkey پشتیبانی نمی‌کند'); return; }
        btn.disabled = true; btn.style.opacity = '.6';
        setSt(st, '', 'در حال آماده‌سازی...');
        try {
            var opts = await (await fetch('?action=passkey_auth_challenge')).json();
            opts.challenge = b64d(opts.challenge);
            if (opts.allowCredentials) opts.allowCredentials = opts.allowCredentials.map(function(c){return Object.assign({}, c, {id: b64d(c.id), transports: ['internal']});});
            opts.hints = ['client-device'];
            opts.userVerification = 'required';
            setSt(st, '', 'لطفاً بیومتریک یا PIN خود را تأیید کنید...');
            var cred = await navigator.credentials.get({publicKey: opts});
            var body = {
                id: cred.id,
                clientDataJSON: b64e(cred.response.clientDataJSON),
                authenticatorData: b64e(cred.response.authenticatorData),
                signature: b64e(cred.response.signature)
            };
            setSt(st, '', 'در حال تأیید...');
            var res = await (await fetch('?action=passkey_auth_verify', {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(body)})).json();
            if (res.ok) {
                setSt(st, 'ok', '✓ ورود موفق...');
                window.location = res.redirect || '?action=dashboard';
            } else {
                throw new Error(res.error || 'خطا');
            }
        } catch (e) {
            btn.disabled = false; btn.style.opacity = '';
            setSt(st, 'e', e.name === 'NotAllowedError' ? 'عملیات لغو شد' : ('خطا: ' + e.message));
        }
    }
    var pkBtn = document.getElementById('pkBtn');
    if (pkBtn) pkBtn.addEventListener('click', pkLogin);
})();
</script>
</body></html>
<?php
    exit;
}

if ($action == 'login_process') {
    verifyCsrf();
    $identifier = trim($_POST['username'] ?? '');
    $p = $_POST['password'] ?? '';
    $json = wants_json();

    if ($identifier === '' || $p === '') {
        if ($json) auth_json_err('invalid');
        header("Location: index.php?error=1"); exit;
    }

    // Lookup by username OR email (case-insensitive for email)
    $st = $pdo->prepare("SELECT username, password, role FROM users
        WHERE username = ? OR email = LOWER(?) LIMIT 1");
    $st->execute([$identifier, $identifier]);
    $ud = $st->fetch();

    if ($ud && password_verify($p, $ud['password'])) {
        session_regenerate_id(true);
        $_SESSION['user'] = $ud['username'];
        $_SESSION['role'] = $ud['role'];
        logActivity($pdo, $ud['username'], 'login', null, 'ورود موفق');
        if ($json) auth_json_ok(['redirect' => '?action=dashboard']);
        header("Location: ?action=dashboard"); exit;
    }

    logActivity($pdo, $identifier ?: 'unknown', 'login_failed', null, 'تلاش ناموفق');
    if ($json) auth_json_err('invalid');
    header("Location: index.php?error=1"); exit;
}

if($action=='logout'){if(isset($_SESSION['user']))logActivity($pdo,$_SESSION['user'],'logout');session_destroy();header("Location: index.php");exit;}

if($action=='upload_process'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    $up=getUserUploadPath($_SESSION['user']);
    $files=normalizeFilesArray($_FILES["fileToUpload"]??null);
    if(empty($files)){header("Location: ?action=dashboard&msg=upload_error");exit;}
    $ok=0;$fail=0;$tooLarge=0;$quota=0;
    $usedBytes=getDirSize($up);
    foreach($files as $f){
        if($f["error"]!==UPLOAD_ERR_OK){$fail++;continue;}
        if($f["size"]>$MAX_FILE_SIZE){$tooLarge++;$fail++;continue;}
        if(($usedBytes+$f["size"])>$MAX_STORAGE_PER_USER){$quota++;$fail++;continue;}
        $on=basename($f["name"]);$ext=strtolower(pathinfo($on,PATHINFO_EXTENSION));
        $tf=$up.$on;$c=1;$nwe=pathinfo($on,PATHINFO_FILENAME);
        while(file_exists($tf)){$tf=$up.$nwe.'_'.$c.'.'.$ext;$c++;}
        if(move_uploaded_file($f["tmp_name"],$tf)){
            logActivity($pdo,$_SESSION['user'],'upload',basename($tf),"حجم: ".formatBytes($f["size"])." | نوع: $ext");
            $usedBytes+=$f["size"];$ok++;
        }else{$fail++;}
    }
    header("Location: ?action=dashboard&".buildUploadStatusQuery($ok,$fail,$tooLarge,$quota));exit;
}

