// ── Short-link sharing: PUBLIC (no auth) page view ──
if($action==='share_view'){
    cleanupExpiredOneTimeShares($pdo);
    $token=$_GET['t']??'';
    $stmt=$pdo->prepare("SELECT * FROM share_links WHERE token = ? LIMIT 1");
    $stmt->execute([$token]);
    $share=$stmt->fetch(PDO::FETCH_ASSOC);

    if(!$share||$share['revoked_at']){
        renderShareErrorPage('این لینک معتبر نیست یا منقضی شده.', 410); exit;
    }
    if($share['is_one_time']&&$share['consumed_at']){
        $isSameIp=($share['consumed_by_ip']===getClientIp());
        $withinGrace=(strtotime($share['consumed_at'])>time()-600);
        if(!($isSameIp&&$withinGrace)){
            renderShareErrorPage('این فایل قبلاً مشاهده شده و دیگر در دسترس نیست.', 410); exit;
        }
    }

    $passwordOk=false;
    if($share['password_hash']){
        $sessionOk = !empty($_SESSION['share_pw_ok_'.$share['token']]);
        $keyOk = isset($_GET['k']) && verifyShareAccessKey($share['token'], $_GET['k']);
        $passwordOk = $sessionOk || $keyOk;
    }else{
        $passwordOk=true;
    }
    if(!$passwordOk){
        renderSharePasswordPage($share, isset($_GET['err']));
        exit;
    }

    $filePath=getUserUploadPath($share['owner']).$share['file_name'];
    if(!file_exists($filePath)||!is_file($filePath)){
        renderShareErrorPage('فایل مورد نظر روی سرور یافت نشد.', 404); exit;
    }

    if($share['is_one_time']&&!$share['consumed_at']){
        $upd=$pdo->prepare(
            "UPDATE share_links
             SET consumed_at = NOW(), consumed_by_ip = ?, consumed_user_agent = ?, view_count = view_count + 1
             WHERE id = ? AND consumed_at IS NULL"
        );
        $upd->execute([getClientIp(), substr($_SERVER['HTTP_USER_AGENT']??'', 0, 255), $share['id']]);
        $stmt->execute([$token]); $share=$stmt->fetch(PDO::FETCH_ASSOC);
    }else{
        $upd=$pdo->prepare("UPDATE share_links SET view_count = view_count + 1 WHERE id = ?");
        $upd->execute([$share['id']]);
    }

    logActivity($pdo, $share['owner'], 'share_link_view', $share['file_name'], 'token='.$token.' ip='.getClientIp());
    renderSharePublicPage($share);
    exit;
}

// ── Short-link sharing: PUBLIC password verification ──
if($action==='share_password'){
    if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405); die('Method not allowed');}
    $token=$_POST['t']??'';
    $password=$_POST['password']??'';

    $stmt=$pdo->prepare("SELECT * FROM share_links WHERE token = ? AND revoked_at IS NULL LIMIT 1");
    $stmt->execute([$token]);
    $share=$stmt->fetch(PDO::FETCH_ASSOC);
    if(!$share||!$share['password_hash']){
        header('Location: ?action=share_view&t='.urlencode($token)); exit;
    }

    $ip=getClientIp();
    if(isShareLinkRateLimited($pdo, $token, $ip)){
        renderShareErrorPage('تلاش‌های بیش از حد. لطفاً ۱۵ دقیقه دیگر تلاش کنید.', 429); exit;
    }

    if(password_verify($password, $share['password_hash'])){
        logShareAttempt($pdo, $token, $ip, true);
        $_SESSION['share_pw_ok_'.$token]=true; // primary: session
        $key = generateShareAccessKey($token); // fallback: HMAC URL param
        header('Location: ?action=share_view&t='.urlencode($token).'&k='.$key); exit;
    }else{
        logShareAttempt($pdo, $token, $ip, false);
        logActivity($pdo, $share['owner'], 'share_link_password_fail', $share['file_name'], 'token='.$token.' ip='.$ip);
        header('Location: ?action=share_view&t='.urlencode($token).'&err=1'); exit;
    }
}

// ── Short-link sharing: PUBLIC download ──
if($action==='share_download'){
    cleanupExpiredOneTimeShares($pdo);
    $token=$_GET['t']??'';
    $stmt=$pdo->prepare("SELECT * FROM share_links WHERE token = ? AND revoked_at IS NULL LIMIT 1");
    $stmt->execute([$token]);
    $share=$stmt->fetch(PDO::FETCH_ASSOC);
    if(!$share){http_response_code(410); die('Link not available');}

    if($share['password_hash']){
        $sessionOk = !empty($_SESSION['share_pw_ok_'.$token]);
        $keyOk = isset($_GET['k']) && verifyShareAccessKey($token, $_GET['k']);
        if(!$sessionOk && !$keyOk){
            header('Location: ?action=share_view&t='.urlencode($token)); exit;
        }
    }

    if($share['is_one_time']){
        $isSameIp=($share['consumed_by_ip']===getClientIp());
        $withinGrace=$share['consumed_at']&&(strtotime($share['consumed_at'])>time()-600);
        if(!$share['consumed_at']||!$isSameIp||!$withinGrace){
            header('Location: ?action=share_view&t='.urlencode($token)); exit;
        }
    }

    $filePath=getUserUploadPath($share['owner']).$share['file_name'];
    if(!file_exists($filePath)||!is_file($filePath)){
        http_response_code(404); die('File not found');
    }

    logActivity($pdo, $share['owner'], 'share_link_download', $share['file_name'], 'token='.$token.' ip='.getClientIp());

    $mime=getFileMimeType($filePath);
    $inlineOk=!empty($_GET['inline'])&&(strpos($mime,'image/')===0||strpos($mime,'video/')===0||strpos($mime,'audio/')===0);
    $disposition=$inlineOk?'inline':'attachment';

    header('Content-Type: '.$mime);
    header('Content-Disposition: '.$disposition.'; filename="'.rawurlencode($share['file_name']).'"');
    header('Content-Length: '.filesize($filePath));
    header('Cache-Control: no-store, no-cache, must-revalidate');
    readfile($filePath);
    exit;
}

// ── Short-link sharing: AUTH create link ──
if($action==='share_create'){
    if(!isset($_SESSION['user'])){header('Location: index.php'); exit;}
    if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405); die('Method not allowed');}
    cleanupExpiredOneTimeShares($pdo);
    verifyCsrf();

    $userRow=$pdo->prepare("SELECT can_share, role FROM users WHERE username = ?");
    $userRow->execute([$_SESSION['user']]);
    $u=$userRow->fetch(PDO::FETCH_ASSOC);
    $isAjax=!empty($_POST['ajax']);
    $forbid=function($key) use ($isAjax){
        if($isAjax){header('Content-Type: application/json'); echo json_encode(['ok'=>false,'error'=>$key]); exit;}
        header('Location: ?action=dashboard&msg='.$key); exit;
    };
    if(!$u||(!$u['can_share']&&$u['role']!=='admin')){$forbid('share_forbidden');}

    $fileName=basename($_POST['file_name']??'');
    $owner=$_POST['owner']??$_SESSION['user'];
    if($owner!==$_SESSION['user']&&$u['role']!=='admin'){$forbid('share_forbidden');}

    $filePath=getUserUploadPath($owner).$fileName;
    if($fileName===''||!file_exists($filePath)||!is_file($filePath)){$forbid('not_found');}

    $password=trim($_POST['password']??'');
    $isOneTime=!empty($_POST['one_time'])?1:0;

    $passwordHash=null;
    if($password!==''){
        if(mb_strlen($password)<4){$forbid('share_pw_short');}
        $passwordHash=password_hash($password, PASSWORD_BCRYPT);
    }

    $token=generateShareToken($pdo);
    $stmt=$pdo->prepare(
        "INSERT INTO share_links (token, owner, file_name, password_hash, is_one_time)
         VALUES (?, ?, ?, ?, ?)"
    );
    $stmt->execute([$token, $owner, $fileName, $passwordHash, $isOneTime]);

    logActivity($pdo, $_SESSION['user'], 'share_link_create', $fileName,
        "owner={$owner} one_time={$isOneTime} password=".($passwordHash?'yes':'no'));

    if($isAjax){
        header('Content-Type: application/json');
        echo json_encode(['ok'=>true,'token'=>$token,'url'=>buildShareUrl($token)]);
        exit;
    }
    header('Location: ?action=my_shares&msg=share_created'); exit;
}

// ── Short-link sharing: AUTH revoke ──
if($action==='share_revoke'){
    if(!isset($_SESSION['user'])){header('Location: index.php'); exit;}
    cleanupExpiredOneTimeShares($pdo);
    $csrfTok=$_GET['csrf_token']??$_POST['csrf_token']??$_GET['csrf']??$_POST['csrf']??'';
    if(empty($csrfTok)||!hash_equals($_SESSION['csrf_token']??'', $csrfTok)){renderCsrfError();}

    $token=$_GET['t']??$_POST['t']??'';
    $stmt=$pdo->prepare("SELECT * FROM share_links WHERE token = ? AND revoked_at IS NULL");
    $stmt->execute([$token]);
    $share=$stmt->fetch(PDO::FETCH_ASSOC);
    if(!$share){header('Location: ?action=my_shares&msg=share_not_found'); exit;}

    $userRow=$pdo->prepare("SELECT role FROM users WHERE username = ?");
    $userRow->execute([$_SESSION['user']]);
    $role=$userRow->fetchColumn();
    if($share['owner']!==$_SESSION['user']&&$role!=='admin'){
        header('Location: ?action=my_shares&msg=share_forbidden'); exit;
    }

    $upd=$pdo->prepare("UPDATE share_links SET revoked_at = NOW() WHERE id = ?");
    $upd->execute([$share['id']]);
    logActivity($pdo, $_SESSION['user'], 'share_link_revoke', $share['file_name'], 'token='.$token);

    header('Location: ?action=my_shares&msg=share_revoked'); exit;
}

// ── Share file with other users (admin only — users must not see other users) ──
if($action=='share_file'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    if(($_SESSION['role']??'')!=='admin'){header("Location: ?action=dashboard&msg=no_permission");exit;}
    $fn=basename($_POST['filename']??'');$owner=$_POST['owner']??'';$targets=$_POST['share_with']??[];
    if(!empty($fn)&&!empty($owner)&&is_array($targets)){
        $fp=getUserUploadPath($owner).$fn;
        if(file_exists($fp)){
            foreach($targets as $tgt){
                $tgt=trim($tgt);if(empty($tgt)||$tgt===$owner)continue;
                $ins=$pdo->prepare("INSERT IGNORE INTO file_shares (original_owner,filename,shared_with,shared_by) VALUES(?,?,?,?)");
                $ins->execute([$owner,$fn,$tgt,$_SESSION['user']]);
            }
            logActivity($pdo,$_SESSION['user'],'share_file',$fn,"صاحب: $owner | با: ".implode(',',$targets));
        }
    }
    $redirect="?action=dashboard&msg=shared";
    if($owner!==$_SESSION['user'])$redirect.="&view_user=".urlencode($owner);
    header("Location: $redirect");exit;
}

// ── Unshare/remove shared file from recipient's view ──
if($action=='unshare_file'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $sid=(int)($_GET['share_id']??0);
    $st=$pdo->prepare("SELECT * FROM file_shares WHERE id=?");$st->execute([$sid]);$sh=$st->fetch();
    if($sh){
        // recipient can remove from their own view, or admin can remove
        if($sh['shared_with']===$_SESSION['user']||$_SESSION['role']==='admin'){
            $pdo->prepare("DELETE FROM file_shares WHERE id=?")->execute([$sid]);
            logActivity($pdo,$_SESSION['user'],'unshare_file',$sh['filename'],"از: ".$sh['shared_with']);
        }
    }
    header("Location: ?action=dashboard&msg=unshared");exit;
}

// ── Remove self from public file access (deprecated: public files are now visible to all users) ──
if($action=='remove_public_access'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    header("Location: ?action=dashboard&tab=public&msg=removed");exit;
}

// ── Get shares for a file (AJAX, admin only) ──
if($action=='get_shares'){
    header('Content-Type: application/json');
    if(!isset($_SESSION['user'])||($_SESSION['role']??'')!=='admin'){echo json_encode(['shares'=>[]]);exit;}
    $fn=basename($_GET['filename']??'');$owner=$_GET['owner']??'';
    $st=$pdo->prepare("SELECT id,shared_with,shared_by,created_at FROM file_shares WHERE original_owner=? AND filename=?");
    $st->execute([$owner,$fn]);
    echo json_encode(['shares'=>$st->fetchAll(PDO::FETCH_ASSOC)]);exit;
}

// ── Get public file access list (AJAX, deprecated: public files are visible to all users) ──
if($action=='get_public_access'){
    header('Content-Type: application/json');
    echo json_encode(['users'=>[]]);exit;
}

if($action=='download'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $fn=basename($_GET['name']??'');$owner=$_GET['owner']??$_SESSION['user'];
    $isPublicDl=isset($_GET['public_file_id']);
    $ps=$pdo->prepare("SELECT can_download,role FROM users WHERE username=?");$ps->execute([$_SESSION['user']]);$pr=$ps->fetch();
    if(!$pr||($pr['role']!=='admin'&&!$pr['can_download'])){header("Location: ?action=dashboard&msg=no_permission");exit;}

    if($isPublicDl){
        // Public file download
        $pfid=(int)$_GET['public_file_id'];
        $pfs=$pdo->prepare("SELECT * FROM public_files WHERE id=?");$pfs->execute([$pfid]);$pf=$pfs->fetch();
        if($pf){
            $fp=$public_base.$pf['filename'];
            if(file_exists($fp)){
                logActivity($pdo,$_SESSION['user'],'download',$pf['filename'],'فایل عمومی');
                header('Content-Type: application/octet-stream');header('Content-Disposition: attachment; filename="'.$pf['filename'].'"');
                header('Content-Length: '.filesize($fp));readfile($fp);exit;
            }
        }
        header("Location: ?action=dashboard&tab=public&msg=not_found");exit;
    }

    // Check access: owner, admin, or shared with user
    $hasAccess=($_SESSION['role']==='admin'||$owner===$_SESSION['user']);
    if(!$hasAccess){
        $sc=$pdo->prepare("SELECT id FROM file_shares WHERE original_owner=? AND filename=? AND shared_with=?");
        $sc->execute([$owner,$fn,$_SESSION['user']]);$hasAccess=(bool)$sc->fetch();
    }
    if(!$hasAccess)die("دسترسی غیرمجاز!");

    $fp=getUserUploadPath($owner).$fn;
    if(file_exists($fp)&&is_file($fp)){
        logActivity($pdo,$_SESSION['user'],'download',$fn,"از: $owner");
        header('Content-Type: application/octet-stream');header('Content-Disposition: attachment; filename="'.$fn.'"');
        header('Content-Length: '.filesize($fp));readfile($fp);exit;
    }
    header("Location: ?action=dashboard&msg=not_found");exit;
}

if($action=='delete_file'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $fn=basename($_GET['name']??'');$owner=$_GET['owner']??$_SESSION['user'];
    if($_SESSION['role']!=='admin'){
        if($owner!==$_SESSION['user'])die("دسترسی غیرمجاز!");
        $dc=$pdo->prepare("SELECT can_delete FROM users WHERE username=?");$dc->execute([$_SESSION['user']]);$dr=$dc->fetch();
        if(!$dr||!$dr['can_delete']){header("Location: ?action=dashboard&msg=no_permission");exit;}
    }
    $fp=getUserUploadPath($owner).$fn;
    if(file_exists($fp)&&is_file($fp)){
        $fsize=filesize($fp);
        $trashFn=time().'_'.preg_replace('/[^a-zA-Z0-9_-]/','_',$owner).'_'.$fn;
        $tp=$trash_base.$trashFn;
        if(rename($fp,$tp)){
            $st=$pdo->prepare("INSERT INTO trash_items (original_owner,original_filename,trash_filename,deleted_by,file_size) VALUES(?,?,?,?,?)");
            $st->execute([$owner,$fn,$trashFn,$_SESSION['user'],$fsize]);
            $pdo->prepare("DELETE FROM file_folders WHERE owner=? AND filename=?")->execute([$owner,$fn]);
            $pdo->prepare("DELETE FROM file_captions WHERE owner=? AND filename=?")->execute([$owner,$fn]);
            logActivity($pdo,$_SESSION['user'],'delete',$fn,"از: $owner | به سطل زباله منتقل شد");
            header("Location: ?action=dashboard&msg=deleted".($owner!==$_SESSION['user']?"&view_user=$owner":""));exit;
        }
    }
    header("Location: ?action=dashboard&msg=not_found");exit;
}

if($action=='rename_file'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
    $on=basename($_POST['old_name']??'');$nn=basename($_POST['new_name']??'');$owner=$_POST['owner']??$_SESSION['user'];
    if(!empty($on)&&!empty($nn)){
        $op=getUserUploadPath($owner).$on;$np=getUserUploadPath($owner).$nn;
        if(file_exists($op)&&!file_exists($np)){
            rename($op,$np);
            $pdo->prepare("UPDATE file_folders SET filename=? WHERE owner=? AND filename=?")->execute([$nn,$owner,$on]);
            $pdo->prepare("UPDATE file_captions SET filename=? WHERE owner=? AND filename=?")->execute([$nn,$owner,$on]);
            logActivity($pdo,$_SESSION['user'],'rename',"$on → $nn","پوشه: $owner");
            header("Location: ?action=dashboard&msg=renamed".($owner!==$_SESSION['user']?"&view_user=$owner":""));exit;
        }
    }
    header("Location: ?action=dashboard&msg=rename_error");exit;
}

if($action=='file_info'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");
    $fn=basename($_GET['name']??'');$owner=$_GET['owner']??$_SESSION['user'];
    if($_SESSION['role']!=='admin'&&$owner!==$_SESSION['user'])die("دسترسی غیرمجاز!");
    $fp=getUserUploadPath($owner).$fn;
    if(!file_exists($fp)||!is_file($fp)){header("Location: ?action=dashboard&msg=not_found");exit;}
    $csrf=generateCsrfToken();
    $existingCaption = getFileCaption($pdo, $owner, $fn);
    $captionMsg = $_GET['msg'] ?? '';
    $info=['name'=>$fn,'size'=>formatSizeUnits($fp),'size_bytes'=>filesize($fp),'mime'=>getFileMimeType($fp),
        'ext'=>strtolower(pathinfo($fn,PATHINFO_EXTENSION)),'modified'=>to_jalali(date("Y-m-d H:i:s",filemtime($fp))),
        'modified_raw'=>date("Y-m-d H:i:s",filemtime($fp)),'owner'=>$owner,
        'permissions'=>decoct(fileperms($fp)&0777),'dimensions'=>getImageDimensions($fp),'md5'=>md5_file($fp)];
    ?><!DOCTYPE html><html lang="fa" dir="rtl"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>بررسی فایل | XCloud</title>
<?= renderHeadAssets() ?>
    <style>@font-face{font-family:'Dana';src:url('data:font/truetype;base64,') format('truetype');font-weight:normal;font-style:normal;}@font-face{font-family:'JetBrains Mono';src:url('data:font/truetype;base64,') format('truetype');unicode-range:U+0030-0039,U+002E,U+002C,U+0025,U+002F;font-weight:normal;font-style:normal;}*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}body{font-family:'Dana','JetBrains Mono',sans-serif;background:#0a0e1a;color:#e2e8f0;min-height:100vh}.app-header{position:sticky;top:0;z-index:1000;background:rgba(10,14,26,.88);backdrop-filter:blur(16px);padding:14px 20px;display:flex;justify-content:space-between;align-items:center;border-bottom:1px solid #1e293b}.back-link{color:#3b82f6;text-decoration:none;font-size:.88rem;font-weight:600}.container{padding:20px;max-width:640px;margin:0 auto}.info-card{background:#111827;border-radius:16px;padding:24px;border:1px solid #1e293b;margin-bottom:20px}.file-icon-big{font-size:3rem;text-align:center;margin-bottom:16px}.file-title{font-size:1.1rem;font-weight:800;text-align:center;margin-bottom:4px;word-break:break-all}.info-row{display:flex;justify-content:space-between;align-items:center;padding:12px 0;border-bottom:1px solid rgba(30,41,59,.5)}.info-row:last-child{border-bottom:none}.info-label{font-size:.8rem;color:#64748b}.info-value{font-size:.85rem;font-weight:600;text-align:left;direction:ltr;max-width:60%;word-break:break-all}.preview-box{margin-top:20px;border-radius:12px;overflow:hidden;background:#0a0e1a;text-align:center}.preview-box img{max-width:100%;height:auto;display:block;margin:0 auto}.hash-value{font-family:monospace;font-size:.72rem;color:#94a3b8}</style>
    </head><body>
    <header class="app-header">
        <a href="?action=dashboard<?php echo $owner!==$_SESSION['user']?'&view_user='.urlencode($owner):'';?>" class="back-link">← بازگشت</a>
        <span style="font-weight:900;font-size:1rem;background:linear-gradient(135deg,#3b82f6,#8b5cf6);-webkit-background-clip:text;-webkit-text-fill-color:transparent;">بررسی فایل</span>
    </header>
    <div class="container"><div class="info-card">
        <div class="file-icon-big"><?php echo getFileIcon($fn);?></div>
        <div class="file-title"><?php echo h($info['name']);?></div>
        <?php if(isGif($fn)):?><div class="preview-box" style="background:#000;display:flex;align-items:center;justify-content:center;position:relative"><img src="<?php echo h($fp);?>?_t=<?php echo filemtime($fp);?>" alt="<?php echo h($fn);?>" style="max-width:100%;height:auto;display:block;background:#000"><span style="position:absolute;top:8px;right:8px;background:rgba(139,92,246,.85);color:#fff;font-size:.66rem;font-weight:800;padding:3px 8px;border-radius:6px;letter-spacing:.5px">GIF</span></div>
        <?php elseif(isImage($fn)):?><div class="preview-box"><img src="<?php echo h($fp);?>" alt="<?php echo h($fn);?>"></div><?php endif;?>
        <?php if(isVideo($fn)):?><div class="preview-box"><video controls style="max-width:100%"><source src="<?php echo h($fp);?>"></video></div><?php endif;?>
        <?php if(isAudio($fn)):?><div class="preview-box" style="padding:20px"><audio controls style="width:100%"><source src="<?php echo h($fp);?>"></audio></div><?php endif;?>
        <?php if(isCaptionable($fn)):?>
        <?php if($captionMsg==='caption_saved'):?>
        <div style="background:rgba(34,197,94,.1);color:#4ade80;padding:8px 12px;border-radius:8px;margin-top:14px;font-size:.78rem">✅ کپشن ذخیره شد</div>
        <?php elseif($captionMsg==='caption_unsupported'):?>
        <div style="background:rgba(245,158,11,.1);color:#fbbf24;padding:8px 12px;border-radius:8px;margin-top:14px;font-size:.78rem">⚠️ کپشن فقط برای عکس و گیف امکان‌پذیر است</div>
        <?php endif;?>
        <form action="?action=set_caption" method="POST" style="margin-top:18px;padding-top:18px;border-top:1px solid #1e293b">
            <div style="font-size:.82rem;font-weight:700;margin-bottom:10px;color:#e2e8f0">📝 کپشن</div>
            <input type="hidden" name="csrf_token" value="<?php echo $csrf;?>">
            <input type="hidden" name="filename" value="<?php echo h($fn);?>">
            <input type="hidden" name="owner" value="<?php echo h($owner);?>">
            <input type="hidden" name="return" value="file_info">
            <textarea name="caption" maxlength="1000" placeholder="کپشن این عکس/گیف را وارد کنید (برای حذف، خالی بگذارید)" style="width:100%;background:#0a0e1a;color:#e2e8f0;border:1.5px solid #1e293b;border-radius:10px;padding:11px 14px;font-family:inherit;font-size:.84rem;min-height:90px;outline:none;resize:vertical;box-sizing:border-box"><?php echo h($existingCaption);?></textarea>
            <button type="submit" style="margin-top:10px;background:linear-gradient(135deg,#3b82f6,#6366f1);color:#fff;border:none;padding:10px 18px;border-radius:10px;font-weight:700;cursor:pointer;font-size:.84rem">ذخیره کپشن</button>
        </form>
        <?php endif;?>
        <div style="margin-top:20px">
            <div class="info-row"><span class="info-label">مالک</span><span class="info-value"><?php echo h($info['owner']);?></span></div>
            <div class="info-row"><span class="info-label">حجم فایل</span><span class="info-value"><?php echo h($info['size']);?> (<?php echo number_format($info['size_bytes']);?> bytes)</span></div>
            <div class="info-row"><span class="info-label">نوع MIME</span><span class="info-value"><?php echo h($info['mime']);?></span></div>
            <div class="info-row"><span class="info-label">پسوند</span><span class="info-value">.<?php echo h($info['ext']);?></span></div>
            <?php if($info['dimensions']):?><div class="info-row"><span class="info-label">ابعاد</span><span class="info-value"><?php echo h($info['dimensions']);?></span></div><?php endif;?>
            <div class="info-row"><span class="info-label">آخرین تغییر</span><span class="info-value"><?php echo h($info['modified']);?></span></div>
            <div class="info-row"><span class="info-label">تاریخ میلادی</span><span class="info-value"><?php echo h($info['modified_raw']);?></span></div>
            <div class="info-row"><span class="info-label">مجوزها</span><span class="info-value"><?php echo h($info['permissions']);?></span></div>
            <div class="info-row"><span class="info-label">MD5 Hash</span><span class="info-value hash-value"><?php echo h($info['md5']);?></span></div>
        </div>
    </div></div>
    <?php
// ================================================================
// PWA Install Popup — XCloud v2
// موبایل: bottom sheet | دسکتاپ: corner toast
// این فایل رو include کن قبل از </body> در همه صفحه‌ها
// ================================================================
?>

<style>@font-face{font-family:'Dana';src:url('data:font/truetype;base64,') format('truetype');font-weight:normal;font-style:normal;}@font-face{font-family:'JetBrains Mono';src:url('data:font/truetype;base64,') format('truetype');unicode-range:U+0030-0039,U+002E,U+002C,U+0025,U+002F;font-weight:normal;font-style:normal;}
/* ---- shared ---- */
#xcloud-pwa-overlay {
    display: none;
    position: fixed;
    inset: 0;
    z-index: 9998;
    background: rgba(0,0,0,0);
    transition: background .3s ease;
    pointer-events: none;
}
#xcloud-pwa-overlay.visible {
    background: rgba(0,0,0,.45);
    pointer-events: auto;
}

/* ==============================
   MOBILE — bottom sheet
   ============================== */
#xcloud-pwa-popup {
    display: none;
    position: fixed;
    z-index: 9999;
    box-sizing: border-box;
    font-family: 'Dana','JetBrains Mono',sans-serif;

    /* mobile default */
    bottom: 0;
    left: 0;
    right: 0;
    width: 100%;
    background: #131c2e;
    border-top: 1px solid rgba(59,130,246,.25);
    border-radius: 24px 24px 0 0;
    padding: 10px 20px 32px;
    transform: translateY(110%);
    transition: transform .4s cubic-bezier(.16,1,.3,1), opacity .4s;
    opacity: 0;
    pointer-events: none;
}
#xcloud-pwa-popup.visible {
    opacity: 1;
    pointer-events: auto;
    transform: translateY(0);
}

.xpwa-handle {
    width: 40px;
    height: 4px;
    background: #2a3a50;
    border-radius: 2px;
    margin: 0 auto 18px;
}
.xpwa-row {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 18px;
}
.xpwa-icon {
    width: 52px;
    height: 52px;
    border-radius: 15px;
    background: linear-gradient(135deg, #3b82f6, #8b5cf6);
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    box-shadow: 0 4px 16px rgba(59,130,246,.3);
}
.xpwa-info { flex: 1; min-width: 0; }
.xpwa-title {
    font-size: .92rem;
    font-weight: 800;
    color: #f1f5f9;
    margin: 0 0 4px;
    line-height: 1.2;
}
.xpwa-sub {
    font-size: .76rem;
    color: #64748b;
    margin: 0;
    line-height: 1.5;
}
.xpwa-actions {
    display: flex;
    gap: 10px;
}
.xpwa-btn-install {
    flex: 1;
    padding: 13px;
    border: none;
    border-radius: 13px;
    background: linear-gradient(135deg, #3b82f6, #6366f1);
    color: white;
    font-size: .88rem;
    font-weight: 800;
    cursor: pointer;
    transition: opacity .2s, transform .15s;
    box-shadow: 0 4px 16px rgba(59,130,246,.25);
}
.xpwa-btn-install:hover { opacity: .9; }
.xpwa-btn-install:active { transform: scale(.97); }
.xpwa-btn-later {
    padding: 13px 18px;
    border: 1px solid #1e293b;
    border-radius: 13px;
    background: transparent;
    color: #475569;
    font-size: .88rem;
    font-weight: 700;
    cursor: pointer;
    transition: background .2s, color .2s;
    white-space: nowrap;
}
.xpwa-btn-later:hover { background: #1e293b; color: #94a3b8; }
#xcloud-pwa-close {
    position: absolute;
    top: 16px;
    left: 16px;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: #1e293b;
    border: none;
    color: #475569;
    font-size: .8rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background .2s, color .2s;
    padding: 0;
    line-height: 1;
}
#xcloud-pwa-close:hover { background: #374151; color: #e2e8f0; }

/* ==============================
   DESKTOP — corner toast (≥640px)
   ============================== */
@media (min-width: 640px) {
    #xcloud-pwa-overlay { display: none !important; }

    #xcloud-pwa-popup {
        bottom: 24px;
        left: 24px;
        right: auto;
        width: 300px;
        border-radius: 20px;
        border: 1px solid rgba(59,130,246,.2);
        padding: 18px;
        transform: translateY(16px);
        box-shadow: 0 16px 48px rgba(0,0,0,.5);
    }
    #xcloud-pwa-popup.visible {
        transform: translateY(0);
    }
    .xpwa-handle { display: none; }
    .xpwa-icon { width: 46px; height: 46px; border-radius: 13px; }
    .xpwa-title { font-size: .86rem; }
    .xpwa-sub { font-size: .73rem; }
    .xpwa-divider {
        height: 1px;
        background: #1e293b;
        margin: 14px 0;
    }
    .xpwa-btn-install { padding: 10px; font-size: .8rem; border-radius: 10px; }
    .xpwa-btn-later  { padding: 10px 14px; font-size: .8rem; border-radius: 10px; }
    #xcloud-pwa-close { top: 12px; left: 12px; width: 24px; height: 24px; font-size: .72rem; }
}
</style>

<div id="xcloud-pwa-overlay"></div>

<div id="xcloud-pwa-popup" role="dialog" aria-label="نصب اپ XCloud">
    <button id="xcloud-pwa-close" aria-label="بستن">✕</button>
    <div class="xpwa-handle"></div>
    <div class="xpwa-row">
        <div class="xpwa-icon">
            <img src="/icons/web-app-manifest-512x512.png" alt="XCloud" style="width:38px;height:38px;border-radius:10px;object-fit:contain;">
        </div>
        <div class="xpwa-info">
            <p class="xpwa-title">نصب XCloud</p>
            <p class="xpwa-sub">اپ را به صفحه اصلی اضافه کنید<br>و بدون مرورگر استفاده کنید</p>
        </div>
    </div>
    <div class="xpwa-divider"></div>
    <div class="xpwa-actions">
        <button class="xpwa-btn-install" id="xcloud-pwa-install">نصب اپ</button>
        <button class="xpwa-btn-later"   id="xcloud-pwa-later">بعداً</button>
    </div>
</div>

<script>
(function () {
    var REMIND_AFTER_DAYS = 1;
    var SHOW_DELAY_MS     = 2500;
    var STORAGE_KEY       = 'xcloud_pwa_dismissed';
    var INSTALLED_KEY     = 'xcloud_pwa_installed';

    var popup      = document.getElementById('xcloud-pwa-popup');
    var overlay    = document.getElementById('xcloud-pwa-overlay');
    var btnClose   = document.getElementById('xcloud-pwa-close');
    var btnInstall = document.getElementById('xcloud-pwa-install');
    var btnLater   = document.getElementById('xcloud-pwa-later');
    var deferredPrompt = null;

    // اگه قبلاً نصب شده یا standalone هست، کاری نکن
    var isStandalone = window.matchMedia('(display-mode: standalone)').matches || window.navigator.standalone === true;
    if (isStandalone) return;

    // شناسایی iOS
    var isIOS = /iphone|ipad|ipod/i.test(navigator.userAgent) && !window.MSStream;

    function shouldShow() {
        if (localStorage.getItem(INSTALLED_KEY)) return false;
        var raw = localStorage.getItem(STORAGE_KEY);
        if (!raw) return true;
        try {
            var days = (Date.now() - JSON.parse(raw).ts) / 86400000;
            return days >= REMIND_AFTER_DAYS;
        } catch (e) { return true; }
    }

    function isMobile() { return window.innerWidth < 640; }

    function showPopup() {
        if (!shouldShow()) return;
        popup.style.display = 'block';
        if (isMobile()) overlay.style.display = 'block';
        requestAnimationFrame(function () {
            requestAnimationFrame(function () {
                popup.classList.add('visible');
                if (isMobile()) overlay.classList.add('visible');
            });
        });
    }

    function hidePopup(permanent) {
        popup.classList.remove('visible');
        overlay.classList.remove('visible');
        setTimeout(function () {
            popup.style.display = 'none';
            overlay.style.display = 'none';
        }, 420);
        if (permanent) {
            localStorage.setItem(INSTALLED_KEY, '1');
        } else {
            localStorage.setItem(STORAGE_KEY, JSON.stringify({ ts: Date.now() }));
        }
    }

    btnClose.addEventListener('click', function () { hidePopup(false); });
    btnLater.addEventListener('click', function () { hidePopup(false); });
    overlay.addEventListener('click', function (e) { if (e.target === overlay) hidePopup(false); });

    // ── iOS Safari: beforeinstallprompt پشتیبانی نمیشه ──────────
    if (isIOS) {
        var titleEl = popup.querySelector('.xpwa-title');
        var subEl   = popup.querySelector('.xpwa-sub');
        if (titleEl) titleEl.textContent = 'نصب روی iPhone / iPad';
        if (subEl)   subEl.innerHTML = 'دکمه <strong>اشتراک‌گذاری</strong> 🔗 را بزنید<br>سپس <strong>«Add to Home Screen»</strong> را انتخاب کنید';
        if (btnInstall) {
            btnInstall.textContent = 'متوجه شدم ✓';
            btnInstall.addEventListener('click', function () { hidePopup(true); });
        }
        setTimeout(showPopup, SHOW_DELAY_MS);
        return;
    }

    // ── Android / Chrome / Desktop ────────────────────────────────
    btnInstall.addEventListener('click', function () {
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        deferredPrompt.userChoice.then(function (r) {
            if (r.outcome === 'accepted') hidePopup(true);
            deferredPrompt = null;
        });
    });

    window.addEventListener('beforeinstallprompt', function (e) {
        e.preventDefault();
        deferredPrompt = e;
        var headerBtn = document.getElementById('pwa-install-btn');
        if (headerBtn) headerBtn.style.display = 'inline-flex';
        setTimeout(showPopup, SHOW_DELAY_MS);
    });

    window.addEventListener('appinstalled', function () {
        hidePopup(true);
        var headerBtn = document.getElementById('pwa-install-btn');
        if (headerBtn) headerBtn.style.display = 'none';
    });

    window.installPWA = function () {
        if (!deferredPrompt) return;
        deferredPrompt.prompt();
        deferredPrompt.userChoice.then(function (r) {
            if (r.outcome === 'accepted') hidePopup(true);
            deferredPrompt = null;
        });
    };
})();
</script>
    </body></html><?php exit;
}

// ── Folder & caption management ──
if($action=='create_folder'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    $name=trim($_POST['folder_name']??'');
    $owner=trim($_POST['owner']??$_SESSION['user']);
    if($_SESSION['role']!=='admin'&&$owner!==$_SESSION['user'])die("دسترسی غیرمجاز!");
    $name=preg_replace('/\s+/',' ',$name);
    if($name===''||mb_strlen($name)>40){
        header("Location: ?action=dashboard&msg=folder_invalid".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;
    }
    if(strcasecmp($name,'all')===0||strcasecmp($name,'همه')===0){
        header("Location: ?action=dashboard&msg=folder_reserved".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;
    }
    $cnt=$pdo->prepare("SELECT COUNT(*) FROM folders WHERE owner=?");$cnt->execute([$owner]);
    if((int)$cnt->fetchColumn()>=XCLOUD_MAX_FOLDERS_PER_USER){
        header("Location: ?action=dashboard&msg=folder_limit".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;
    }
    try{
        $maxPos=$pdo->prepare("SELECT COALESCE(MAX(position),0)+1 FROM folders WHERE owner=?");
        $maxPos->execute([$owner]);$pos=(int)$maxPos->fetchColumn();
        $ins=$pdo->prepare("INSERT INTO folders (owner,name,position) VALUES(?,?,?)");
        $ins->execute([$owner,$name,$pos]);
        $newId=(int)$pdo->lastInsertId();
        logActivity($pdo,$_SESSION['user'],'folder_create',$name,"برای: $owner");
        header("Location: ?action=dashboard&folder=".$newId.($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):'')."&msg=folder_created");exit;
    }catch(PDOException $e){
        header("Location: ?action=dashboard&msg=folder_dup".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;
    }
}

if($action=='rename_folder'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    $fid=(int)($_POST['folder_id']??0);
    $name=trim($_POST['folder_name']??'');
    $st=$pdo->prepare("SELECT * FROM folders WHERE id=?");$st->execute([$fid]);$fr=$st->fetch();
    if(!$fr){header("Location: ?action=dashboard&msg=folder_not_found");exit;}
    if($_SESSION['role']!=='admin'&&$fr['owner']!==$_SESSION['user'])die("دسترسی غیرمجاز!");
    $name=preg_replace('/\s+/',' ',$name);
    if($name===''||mb_strlen($name)>40){
        header("Location: ?action=dashboard&folder=$fid&msg=folder_invalid".($fr['owner']!==$_SESSION['user']?'&view_user='.urlencode($fr['owner']):''));exit;
    }
    try{
        $up=$pdo->prepare("UPDATE folders SET name=? WHERE id=?");
        $up->execute([$name,$fid]);
        logActivity($pdo,$_SESSION['user'],'folder_rename',$name,"id=$fid");
        header("Location: ?action=dashboard&folder=$fid&msg=folder_renamed".($fr['owner']!==$_SESSION['user']?'&view_user='.urlencode($fr['owner']):''));exit;
    }catch(PDOException $e){
        header("Location: ?action=dashboard&folder=$fid&msg=folder_dup".($fr['owner']!==$_SESSION['user']?'&view_user='.urlencode($fr['owner']):''));exit;
    }
}

if($action=='delete_folder'){
