if($action=='move_file'){
    if(!isset($_SESSION['user']))die("خطای امنیتی!");verifyCsrf();
    $fn=basename($_POST['filename']??'');
    $owner=trim($_POST['owner']??$_SESSION['user']);
    $folderId=(int)($_POST['folder_id']??0);
    if($_SESSION['role']!=='admin'&&$owner!==$_SESSION['user'])die("دسترسی غیرمجاز!");
    if($fn===''){header("Location: ?action=dashboard&msg=not_found".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;}
    if(!file_exists(getUserUploadPath($owner).$fn)){header("Location: ?action=dashboard&msg=not_found".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;}
    if($folderId>0){
        $st=$pdo->prepare("SELECT id FROM folders WHERE id=? AND owner=?");
        $st->execute([$folderId,$owner]);
        if(!$st->fetch()){header("Location: ?action=dashboard&msg=folder_not_found".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;}
        $up=$pdo->prepare("INSERT INTO file_folders (owner,filename,folder_id) VALUES(?,?,?) ON DUPLICATE KEY UPDATE folder_id=VALUES(folder_id)");
        $up->execute([$owner,$fn,$folderId]);
        logActivity($pdo,$_SESSION['user'],'file_move',$fn,"به پوشه id=$folderId");
        header("Location: ?action=dashboard&folder=$folderId&msg=file_moved".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;
    }else{
        $pdo->prepare("DELETE FROM file_folders WHERE owner=? AND filename=?")->execute([$owner,$fn]);
        logActivity($pdo,$_SESSION['user'],'file_move',$fn,'به همه');
        header("Location: ?action=dashboard&msg=file_moved".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;
    }
}

if($action=='set_caption'){
