    $fn=basename($_POST['filename']??'');
    $owner=trim($_POST['owner']??$_SESSION['user']);
    $caption=trim((string)($_POST['caption']??''));
    if($_SESSION['role']!=='admin'&&$owner!==$_SESSION['user'])die("دسترسی غیرمجاز!");
    if($fn===''||!file_exists(getUserUploadPath($owner).$fn)){header("Location: ?action=dashboard&msg=not_found".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):''));exit;}
    if(!isCaptionable($fn)){
        header("Location: ?action=file_info&name=".urlencode($fn).($owner!==$_SESSION['user']?'&owner='.urlencode($owner):'')."&msg=caption_unsupported");exit;
    }
    if(mb_strlen($caption)>1000)$caption=mb_substr($caption,0,1000);
    if($caption===''){
        $pdo->prepare("DELETE FROM file_captions WHERE owner=? AND filename=?")->execute([$owner,$fn]);
    }else{
        $up=$pdo->prepare("INSERT INTO file_captions (owner,filename,caption) VALUES(?,?,?) ON DUPLICATE KEY UPDATE caption=VALUES(caption)");
        $up->execute([$owner,$fn,$caption]);
    }
    logActivity($pdo,$_SESSION['user'],'caption_set',$fn,"len=".mb_strlen($caption));
    $back=$_POST['return']??'file_info';
    if($back==='dashboard'){
        $folderQ=isset($_POST['folder'])?'&folder='.(int)$_POST['folder']:'';
        header("Location: ?action=dashboard$folderQ".($owner!==$_SESSION['user']?'&view_user='.urlencode($owner):'')."&msg=caption_saved");
    }else{
        header("Location: ?action=file_info&name=".urlencode($fn).($owner!==$_SESSION['user']?'&owner='.urlencode($owner):'')."&msg=caption_saved");
    }
    exit;
}

if($action=='add_user'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin')die("دسترسی غیرمجاز!");verifyCsrf();
