    $cd=isset($_POST['can_download'])?1:0;$ccp=isset($_POST['can_change_password'])?1:0;$cdel=isset($_POST['can_delete'])?1:0;$csh=isset($_POST['can_share'])?1:0;
    if($nr==='admin'){$cd=1;$ccp=1;$cdel=1;$csh=1;}
    if(!empty($nu)&&!empty($np)&&strlen($nu)>=3&&strlen($np)>=4){
        $ex=$pdo->prepare("SELECT id FROM users WHERE username=?");$ex->execute([$nu]);
        if(!$ex->fetch()){$h=password_hash($np,PASSWORD_DEFAULT);
            $s=$pdo->prepare("INSERT INTO users (username,password,role,can_download,can_change_password,can_delete,can_share) VALUES(?,?,?,?,?,?,?)");
            $s->execute([$nu,$h,$nr,$cd,$ccp,$cdel,$csh]);getUserUploadPath($nu);logActivity($pdo,$_SESSION['user'],'add_user',$nu,"نقش: $nr");
            header("Location: ?action=users&msg=user_added");exit;}
