<div class="container">
  <?php if ($msg === 'saved'): ?><div class="ok-banner">✅ تنظیمات ذخیره شد</div><?php endif; ?>
  <?php if ($msg === 'ran' && $runNow): ?>
    <div class="ok-banner">🔄 اجرای دستی انجام شد — <?= (int)$runNow['scanned'] ?> پیام بررسی شد، <?= (int)$runNow['matched'] ?> تطبیق</div>
  <?php endif; ?>

  <div class="card">
    <h3>📊 وضعیت کرون</h3>
