    } else {
      box.className = 'testbox show fail';
      box.textContent = '✗ ' + (j.error || 'خطای ناشناخته');
    }
  } catch (e) {
    box.className = 'testbox show fail';
    box.textContent = '✗ خطای شبکه: ' + e.message;
  }
});
</script>
