    <script>
    function renameBg(id, current) {
        var name = prompt('عنوان جدید:', current);
        if (name === null) return;
        var f = document.createElement('form');
        f.method = 'POST'; f.action = '?action=bg_rename';
        f.style.display = 'none';
        f.innerHTML = '<input name="csrf_token" value="<?=h($csrf)?>"><input name="id" value="'+id+'">';
        var labelIn = document.createElement('input');
        labelIn.name = 'label'; labelIn.value = name;
        f.appendChild(labelIn);
        document.body.appendChild(f); f.submit();
    }
    </script>
