if($action=='bg_upload'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin'){header("Location: index.php");exit;}
    verifyCsrf();
    if(empty($_FILES['bg_file'])||$_FILES['bg_file']['error']!==UPLOAD_ERR_OK){
        header("Location: ?action=bg_admin&msg=invalid");exit;
    }
    $f = $_FILES['bg_file'];
    if ($f['size'] > 8 * 1024 * 1024) {header("Location: ?action=bg_admin&msg=too_big");exit;}
    $info = @getimagesize($f['tmp_name']);
    if (!$info) {header("Location: ?action=bg_admin&msg=bad_type");exit;}
    $allowed = ['image/jpeg' => 'jpg', 'image/png' => 'png', 'image/webp' => 'webp'];
    if (!isset($allowed[$info['mime']])) {header("Location: ?action=bg_admin&msg=bad_type");exit;}
    if ($info[0] < 1280 || $info[1] < 720) {header("Location: ?action=bg_admin&msg=bad_type");exit;}
    if ($info[0] > 3840 || $info[1] > 2160) {header("Location: ?action=bg_admin&msg=bad_type");exit;}
    $ext = $allowed[$info['mime']];
    $fname = 'bg_' . bin2hex(random_bytes(10)) . '.' . $ext;
    $dst = $bg_base . $fname;
    if (!move_uploaded_file($f['tmp_name'], $dst)) {
        header("Location: ?action=bg_admin&msg=invalid");exit;
    }
    @chmod($dst, 0644);
    $label = trim($_POST['label']??'');
    if (mb_strlen($label) > 120) $label = mb_substr($label, 0, 120);
    $maxSort = (int)$pdo->query("SELECT COALESCE(MAX(sort_order),0)+1 FROM bg_gallery")->fetchColumn();
    $st = $pdo->prepare("INSERT INTO bg_gallery (filename,label,width,height,size_bytes,mime_type,uploaded_by,sort_order) VALUES (?,?,?,?,?,?,?,?)");
    $st->execute([$fname, $label?:null, $info[0], $info[1], $f['size'], $info['mime'], $_SESSION['user'], $maxSort]);
    logActivity($pdo, $_SESSION['user'], 'bg_upload', $fname, "label:".($label?:'(none)')." dims:{$info[0]}x{$info[1]}");
    header("Location: ?action=bg_admin&msg=uploaded");exit;
}

if($action=='bg_delete'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin'){header("Location: index.php");exit;}
    verifyCsrf();
    $id = (int)($_POST['id']??0);
    if ($id <= 0) {header("Location: ?action=bg_admin&msg=invalid");exit;}
    $st = $pdo->prepare("SELECT filename FROM bg_gallery WHERE id = ? LIMIT 1");
    $st->execute([$id]);
    $row = $st->fetch();
    if ($row) {
        $p = $bg_base . $row['filename'];
        if (file_exists($p)) @unlink($p);
        $pdo->prepare("DELETE FROM bg_user_pref WHERE bg_id = ?")->execute([$id]);
        $pdo->prepare("DELETE FROM bg_gallery WHERE id = ?")->execute([$id]);
        logActivity($pdo, $_SESSION['user'], 'bg_delete', $row['filename'], "id:$id");
    }
    header("Location: ?action=bg_admin&msg=deleted");exit;
}

if($action=='bg_rename'){
    if(!isset($_SESSION['user'])||$_SESSION['role']!=='admin'){header("Location: index.php");exit;}
    verifyCsrf();
    $id = (int)($_POST['id']??0);
    $label = trim($_POST['label']??'');
    if (mb_strlen($label) > 120) $label = mb_substr($label, 0, 120);
    if ($id > 0) {
        $pdo->prepare("UPDATE bg_gallery SET label = ? WHERE id = ?")->execute([$label?:null, $id]);
        logActivity($pdo, $_SESSION['user'], 'bg_rename', "id:$id", "new_label:".($label?:'(empty)'));
    }
    header("Location: ?action=bg_admin&msg=renamed");exit;
}

if($action=='bg_set'){
    if(!isset($_SESSION['user'])){http_response_code(401);exit;}
    verifyCsrf();
    $bgId = isset($_POST['bg_id']) ? (int)$_POST['bg_id'] : 0;
    $username = $_SESSION['user'];
    if ($bgId === 0) {
        $pdo->prepare("DELETE FROM bg_user_pref WHERE username = ?")->execute([$username]);
        $resp = ['ok'=>true,'bg_id'=>0,'url'=>null];
    } else {
        $st = $pdo->prepare("SELECT filename FROM bg_gallery WHERE id = ? AND is_active = 1");
        $st->execute([$bgId]);
        $bg = $st->fetch();
        if (!$bg) {http_response_code(404);header('Content-Type: application/json');echo json_encode(['ok'=>false,'error'=>'not_found']);exit;}
        $pdo->prepare("INSERT INTO bg_user_pref (username, bg_id) VALUES (?, ?) ON DUPLICATE KEY UPDATE bg_id = VALUES(bg_id)")->execute([$username, $bgId]);
        $resp = ['ok'=>true,'bg_id'=>$bgId,'url'=>$bg_base.$bg['filename']];
    }
    header('Content-Type: application/json; charset=utf-8');
    echo json_encode($resp);
    exit;
}

