// LOGIN PAGE
// ================================================================
if($action=='index'){
    if(isset($_SESSION['user'])){header("Location: ?action=dashboard");exit;}
    // All auth flows now live in auth_shell. Preserve error/msg/view params.
    $passthroughs = [];
    foreach (['error','msg','view'] as $k) {
        if (isset($_GET[$k])) $passthroughs[$k] = (string)$_GET[$k];
    }
    if (empty($passthroughs['view'])) $passthroughs['view'] = 'login';
    $qs = http_build_query($passthroughs);
    header("Location: ?action=auth_shell&$qs"); exit;
}

// ================================================================
// DASHBOARD
// ================================================================
elseif($action=='dashboard'){
    if(!isset($_SESSION['user'])){header("Location: index.php");exit;}
    cleanupExpiredOneTimeShares($pdo);
    $role=$_SESSION['role'];$csrf=generateCsrfToken();$search=trim($_GET['search']??'');
    $activeTab=$_GET['tab']??'private';if(!in_array($activeTab,['private','public']))$activeTab='private';
    $viewUser=($role==='admin'&&isset($_GET['view_user']))?trim($_GET['view_user']):$_SESSION['user'];
    $upload_path=getUserUploadPath($viewUser);
    $allUsernames=($role==='admin')?$pdo->query("SELECT username FROM users ORDER BY username ASC")->fetchAll(PDO::FETCH_COLUMN):[];
    $allUsernamesAll=$pdo->query("SELECT username FROM users ORDER BY username ASC")->fetchAll(PDO::FETCH_COLUMN);
    $files=is_dir($upload_path)?array_diff(scandir($upload_path),['..','.']):[];
    $ps=$pdo->prepare("SELECT can_download,can_change_password,can_delete,can_share FROM users WHERE username=?");$ps->execute([$_SESSION['user']]);$perms=$ps->fetch();
    $canDownload=($role==='admin')?true:(bool)($perms['can_download']??0);
    $canChangePass=($role==='admin')?true:(bool)($perms['can_change_password']??0);
    $canDelete=($role==='admin')?true:(bool)($perms['can_delete']??0);
    $canShare=($role==='admin')?true:(bool)($perms['can_share']??0);

    // Shared files: files shared WITH the current view user
    $ss=$pdo->prepare("SELECT fs.*, fs.id as share_id FROM file_shares fs WHERE fs.shared_with=? ORDER BY fs.created_at DESC");
    $ss->execute([$viewUser]);$sharedWithMe=$ss->fetchAll(PDO::FETCH_ASSOC);

    // Public files (visible to all logged-in users)
    $publicFiles=[];
    if($activeTab==='public'){
        $pfs=$pdo->query("SELECT * FROM public_files ORDER BY id DESC");$publicFiles=$pfs->fetchAll(PDO::FETCH_ASSOC);
    }
    // Folder management
    $userFolders = getUserFolders($pdo, $viewUser);
    $fileFolderMap = getFileFolderMap($pdo, $viewUser);
    $fileCaptionsMap = getFileCaptionsMap($pdo, $viewUser);
    $folderIdsValid = array_map(function($f){return (int)$f['id'];}, $userFolders);
    $activeFolder = isset($_GET['folder']) ? (int)$_GET['folder'] : 0;
    if($activeFolder !== 0 && !in_array($activeFolder, $folderIdsValid, true)) $activeFolder = 0;
    $foldersById = [];
    foreach($userFolders as $uf){ $foldersById[(int)$uf['id']] = $uf; }
    $folderCounts = ['all'=>0, 0=>0];
    foreach($userFolders as $uf){ $folderCounts[(int)$uf['id']] = 0; }
    foreach($files as $_f){
        if($_f==='public')continue;
        $_full = $upload_path.$_f;
        if(!is_file($_full))continue;
        $folderCounts['all']++;
        $fid = isset($fileFolderMap[$_f]) && in_array($fileFolderMap[$_f], $folderIdsValid, true) ? $fileFolderMap[$_f] : 0;
        if(!isset($folderCounts[$fid]))$folderCounts[$fid]=0;
        $folderCounts[$fid]++;
    }
    if($search!=='')$files=array_filter($files,function($f)use($search){return stripos($f,$search)!==false;});
    if($activeTab==='private' && $activeFolder > 0){
        $files = array_filter($files, function($f) use ($fileFolderMap, $activeFolder, $folderIdsValid){
            if(!isset($fileFolderMap[$f]))return false;
            $fid = (int)$fileFolderMap[$f];
            if(!in_array($fid, $folderIdsValid, true))return false;
            return $fid === $activeFolder;
        });
    }
    usort($files,function($a,$b)use($upload_path){return filemtime($upload_path.$b)-filemtime($upload_path.$a);});
    $totalFiles=count(array_diff(scandir($upload_path),['.','..']));
    $storageUsed=getDirSize($upload_path);$storagePercent=round(($storageUsed/$MAX_STORAGE_PER_USER)*100,1);
    $msgs=['success'=>['✅','فایل آپلود شد'],'text_success'=>['✅','متن ذخیره شد'],'admin_text_success'=>['✅','متن برای کاربر ذخیره شد'],'deleted'=>['🗑️','فایل به سطل زباله رفت'],
        'renamed'=>['✏️','نام فایل تغییر کرد'],'upload_error'=>['❌','خطا در آپلود'],'too_large'=>['⚠️','حجم بیش از 200MB'],
        'quota_exceeded'=>['⚠️','فضا پر شده'],'not_found'=>['❌','فایل یافت نشد'],
        'password_changed'=>['✅','رمز تغییر کرد'],'password_error'=>['❌','خطا در تغییر رمز'],
        'no_permission'=>['🔒','دسترسی ندارید'],'rename_error'=>['❌','خطا در تغییر نام'],
        'shared'=>['✅','فایل با موفقیت اشتراک‌گذاری شد'],'unshared'=>['✅','اشتراک‌گذاری حذف شد'],
        'share_created'=>['✅','لینک اشتراک با موفقیت ساخته شد'],'share_revoked'=>['🚫','لینک اشتراک لغو شد'],
        'share_forbidden'=>['🔒','شما اجازه اشتراک‌گذاری این فایل را ندارید'],
        'share_pw_short'=>['⚠️','رمز عبور باید حداقل ۴ کاراکتر باشد'],
        'share_not_found'=>['❌','لینک اشتراک یافت نشد'],
        'access_updated'=>['✅','دسترسی‌ها بروزرسانی شد'],'removed'=>['✅','دسترسی حذف شد'],
        'partial_success'=>['⚠️','بخشی از فایل‌ها آپلود شد'],
        'welcome'=>['🎉','خوش آمدید! ثبت‌نام شما با موفقیت تکمیل شد'],
        'folder_created'=>['📁','پوشه ساخته شد'],'folder_renamed'=>['✏️','نام پوشه تغییر کرد'],
        'folder_deleted'=>['🗑️','پوشه حذف شد'],'folder_limit'=>['⚠️','حداکثر '.XCLOUD_MAX_FOLDERS_PER_USER.' پوشه قابل ساخت است'],
        'folder_invalid'=>['❌','نام پوشه نامعتبر است'],'folder_dup'=>['⚠️','پوشه‌ای با همین نام وجود دارد'],
        'folder_reserved'=>['⚠️','این نام رزرو شده است'],'folder_not_found'=>['❌','پوشه یافت نشد'],
        'file_moved'=>['📂','فایل منتقل شد'],'caption_saved'=>['📝','کپشن ذخیره شد'],
        'caption_unsupported'=>['⚠️','کپشن فقط برای عکس و گیف امکان‌پذیر است']];
    $msg=$_GET['msg']??'';
    ?><!DOCTYPE html><html lang="fa" dir="rtl"><head>
    <meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,user-scalable=no">
    <title>XCloud — داشبورد</title>
<?= renderHeadAssets() ?>
    <style>@font-face{font-family:'Dana';src:url('data:font/truetype;base64,') format('truetype');font-weight:normal;font-style:normal;}@font-face{font-family:'JetBrains Mono';src:url('data:font/truetype;base64,') format('truetype');unicode-range:U+0030-0039,U+002E,U+002C,U+0025,U+002F;font-weight:normal;font-style:normal;}
    :root{--bg:#0a0e1a;--surface:#111827;--surface-2:#1a2235;--border:#1e293b;--border-light:#2a3548;--primary:#3b82f6;--primary-glow:rgba(59,130,246,.15);--purple:#8b5cf6;--danger:#ef4444;--success:#22c55e;--warning:#f59e0b;--text:#e2e8f0;--text-dim:#64748b;--text-muted:#475569;--r:14px;--r-sm:10px;--glass-bg:rgba(17,24,39,.55);--glass-border:rgba(255,255,255,.08);--glass-blur:14px;--glass-saturate:1.4;--bg-overlay:rgba(10,14,26,.62);--user-bg-image:none}
    *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}
    body{font-family:'Dana','JetBrains Mono',sans-serif;background:var(--bg);color:var(--text);min-height:100vh}
    button,input,select,textarea,optgroup,a,label{font-family:inherit}
    body.has-custom-bg{background:linear-gradient(var(--bg-overlay),var(--bg-overlay)),var(--bg) var(--user-bg-image) center/cover fixed no-repeat}
    body.has-custom-bg .section-card,
    body.has-custom-bg .modal-box,
    body.has-custom-bg .file-card,
    body.has-custom-bg .drop-zone,
    body.has-custom-bg .stat-card,
    body.has-custom-bg .tab-bar,
    body.has-custom-bg .folder-tab-bar,
    body.has-custom-bg .upload-card{
        background:var(--glass-bg)!important;
        backdrop-filter:blur(var(--glass-blur)) saturate(var(--glass-saturate));
        -webkit-backdrop-filter:blur(var(--glass-blur)) saturate(var(--glass-saturate));
        border-color:var(--glass-border)
    }
    body.has-custom-bg .file-card:hover{border-color:rgba(255,255,255,.16)}
    body.has-custom-bg .app-header{background:rgba(5,8,16,.92)!important;backdrop-filter:blur(20px) saturate(1.4);-webkit-backdrop-filter:blur(20px) saturate(1.4);border-bottom-color:rgba(255,255,255,.08)}
    @media (hover:hover) and (pointer:fine){body.has-custom-bg .app-header:hover{background:rgba(3,6,12,.96)!important}}
    body.has-custom-bg .empty-state{background:var(--glass-bg);backdrop-filter:blur(var(--glass-blur)) saturate(var(--glass-saturate));-webkit-backdrop-filter:blur(var(--glass-blur)) saturate(var(--glass-saturate));border:1px solid var(--glass-border);border-radius:var(--r);color:var(--text)}
    body.has-custom-bg .empty-state .icon{opacity:.85}
    body.has-custom-bg .empty-state p{color:var(--text)}
    body.has-custom-bg .user-chip:not(.active),
    body.has-custom-bg .tab-btn:not(.active){background:rgba(255,255,255,.04);border-color:var(--glass-border)}
    body.has-custom-bg .txt-preview,
    body.has-custom-bg .file-caption,
    body.has-custom-bg .locked-badge,
    body.has-custom-bg .view-banner{
        background:rgba(15,23,42,.45);
        backdrop-filter:blur(8px);
        -webkit-backdrop-filter:blur(8px);
        border-color:var(--glass-border)
    }
    @supports not ((backdrop-filter: blur(1px)) or (-webkit-backdrop-filter: blur(1px))){
        body.has-custom-bg .section-card,
        body.has-custom-bg .modal-box,
        body.has-custom-bg .file-card,
        body.has-custom-bg .drop-zone,
        body.has-custom-bg .stat-card,
        body.has-custom-bg .tab-bar,
        body.has-custom-bg .folder-tab-bar,
        body.has-custom-bg .upload-card,
        body.has-custom-bg .empty-state{background:rgba(17,24,39,.92)!important}
        body.has-custom-bg .app-header{background:rgba(5,8,16,.98)!important}
    }
    .section-card,.modal-box,.file-card,.drop-zone,.stat-card,.tab-bar,.folder-tab-bar{transition:background .3s ease,backdrop-filter .3s ease,border-color .3s ease}

    /* HEADER */
    .app-header{position:sticky;top:0;z-index:1000;background:rgba(10,14,26,.94);backdrop-filter:blur(16px);border-bottom:1px solid var(--border);transition:padding .28s cubic-bezier(.4,0,.2,1),background .28s ease,border-color .28s ease}
    @media (hover:hover) and (pointer:fine){
        .app-header:hover{background:rgba(10,14,26,.97);border-bottom-color:var(--border-light)}
        @media(min-width:900px){
            .app-header .header-inner{transition:padding .28s cubic-bezier(.4,0,.2,1)}
            .app-header:hover .header-inner{padding-top:14px;padding-bottom:14px}
        }
    }
    .header-inner{display:flex;justify-content:space-between;align-items:center;padding:10px 20px;max-width:1280px;margin:0 auto}
    .header-brand{display:flex;align-items:center;gap:8px}
    .header-brand span{font-weight:900;font-size:1.1rem;background:linear-gradient(135deg,var(--primary),var(--purple));-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent}
    .logo-link{position:relative;display:inline-flex;align-items:center;gap:8px;text-decoration:none;padding:6px 12px;border-radius:10px;cursor:pointer}
    .logo-link::before{content:'';position:absolute;inset:0;background:linear-gradient(135deg,rgba(59,130,246,.3),rgba(139,92,246,.3));border-radius:10px;opacity:0;filter:blur(12px);transition:opacity .25s;z-index:-1;pointer-events:none}
    .logo-icon{display:inline-block;transition:transform .3s cubic-bezier(.34,1.4,.4,1),filter .3s ease}
    @media (hover:hover) and (pointer:fine){
        .logo-link:hover::before{opacity:1}
        .logo-link:hover .logo-icon{filter:drop-shadow(0 0 14px rgba(99,102,241,.7));transform:scale(1.06) rotate(-2deg)}
        .logo-link:hover .logo-text{filter:brightness(1.2)}
    }
    .logo-icon.spinning{animation:logoIconSpin .35s ease-out}
    @keyframes logoIconSpin{to{transform:rotate(360deg)}}
    .logo-text{background:linear-gradient(135deg,#3b82f6,#8b5cf6);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;font-weight:900;font-size:1.1rem}
    .header-actions{display:flex;align-items:center;gap:5px;flex-wrap:wrap}
    .nav-btn{display:inline-flex;align-items:center;gap:4px;padding:6px 10px;border-radius:8px;font-size:.72rem;font-weight:700;text-decoration:none;border:none;cursor:pointer;white-space:nowrap;line-height:1;transition:transform .22s cubic-bezier(.34,1.4,.4,1),box-shadow .22s ease,background .22s ease,filter .22s ease,color .22s ease;transform-origin:center;will-change:transform}
    @media (hover:hover) and (pointer:fine){
        .nav-btn:hover:not(.locked):not([disabled]){transform:translateY(-1px) scale(1.06);filter:brightness(1.18) saturate(1.1)}
        .nav-btn.nb-user:hover{box-shadow:0 0 0 1px rgba(59,130,246,.4),0 0 16px -2px rgba(59,130,246,.5)}
        .nav-btn.nb-pass:hover:not(.locked){box-shadow:0 0 0 1px rgba(139,92,246,.4),0 0 16px -2px rgba(139,92,246,.5)}
        .nav-btn.nb-trash:hover{box-shadow:0 0 0 1px rgba(239,68,68,.4),0 0 16px -2px rgba(239,68,68,.5)}
        .nav-btn.nb-log:hover{box-shadow:0 0 0 1px rgba(245,158,11,.4),0 0 16px -2px rgba(245,158,11,.5)}
        .nav-btn.nb-users:hover{box-shadow:0 0 0 1px rgba(34,197,94,.4),0 0 16px -2px rgba(34,197,94,.5)}
        .nav-btn.nb-logout:hover{box-shadow:0 0 0 1px rgba(239,68,68,.4),0 0 16px -2px rgba(239,68,68,.5)}
        .nav-btn.nb-share:hover,.nav-btn.nb-bg:hover{box-shadow:0 0 0 1px rgba(59,130,246,.4),0 0 16px -2px rgba(59,130,246,.5)}
    }
    .nav-btn:active:not(.locked):not([disabled]){transform:translateY(0) scale(.98);transition-duration:.08s}
    .nav-btn svg{width:13px;height:13px;flex-shrink:0}
    .nb-user{background:var(--primary-glow);color:var(--primary);border:1px solid rgba(59,130,246,.2)}
    .nb-pass{background:rgba(139,92,246,.1);color:#a78bfa;border:1px solid rgba(139,92,246,.15)}
    .nb-pass:hover{background:rgba(139,92,246,.2)}
    .nb-pass.locked{opacity:.4;cursor:not-allowed}
    .nb-trash{background:rgba(239,68,68,.1);color:var(--danger);border:1px solid rgba(239,68,68,.15);position:relative}
    .nb-trash:hover{background:rgba(239,68,68,.2)}
    .trash-badge{position:absolute;top:-5px;right:-5px;background:var(--danger);color:white;font-size:.6rem;font-weight:800;width:16px;height:16px;border-radius:50%;display:flex;align-items:center;justify-content:center;line-height:1}
    .nb-log{background:rgba(245,158,11,.1);color:var(--warning);border:1px solid rgba(245,158,11,.15)}
    .nb-log:hover{background:rgba(245,158,11,.2)}
    .nb-users{background:rgba(34,197,94,.1);color:var(--success);border:1px solid rgba(34,197,94,.15)}
    .nb-users:hover{background:rgba(34,197,94,.2)}
    .nb-logout{background:rgba(239,68,68,.1);color:var(--danger);border:1px solid rgba(239,68,68,.15)}
    .nb-logout:hover{background:rgba(239,68,68,.2)}
    .header-search{padding:0 20px 10px;max-width:1280px;margin:0 auto}
    .header-search form{position:relative}
    .header-search input{width:100%;background:rgba(17,24,39,.7);border:1.5px solid var(--border);padding:8px 14px 8px 34px;border-radius:10px;color:var(--text);font-size:.82rem;outline:none;transition:.25s}
    .header-search input:focus{border-color:var(--primary);box-shadow:0 0 0 3px var(--primary-glow)}
    .search-icon{position:absolute;left:10px;top:50%;transform:translateY(-50%);color:var(--text-dim);pointer-events:none}

    /* MAIN LAYOUT */
    .main-container{max-width:1280px;margin:0 auto;padding:16px 20px}
    @media(min-width:900px){
        .dashboard-grid{display:grid;grid-template-columns:290px 1fr;gap:20px;align-items:start}
        .left-panel{position:sticky;top:82px}
        .file-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}
    }
    @media(max-width:899px){
        .main-container{padding:12px 14px}
        .file-grid{display:flex;flex-direction:column;gap:8px}
    }

    /* USER SWITCHER */
    .user-switcher{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px}
    .user-chip{padding:5px 12px;border-radius:18px;font-size:.73rem;font-weight:600;text-decoration:none;border:1px solid var(--border);background:var(--surface);color:var(--text-dim);transition:all .2s}
    .user-chip:hover{border-color:var(--primary);color:var(--text)}
    .user-chip.active{background:var(--primary-glow);border-color:var(--primary);color:var(--primary)}

    /* STATS */
    .stats-section{margin-bottom:14px}
    .stat-row{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px}
    .stat-card{background:var(--surface);border-radius:var(--r-sm);padding:12px 14px;border:1px solid var(--border)}
    .stat-label{font-size:.68rem;color:var(--text-dim);margin-bottom:4px}
    .stat-value{font-size:1.1rem;font-weight:800}
    .storage-bar{width:100%;height:5px;background:var(--border);border-radius:3px;margin-top:8px;overflow:hidden}
    .storage-fill{height:100%;border-radius:3px;transition:width .5s}
    .storage-note{font-size:.62rem;color:var(--text-dim);margin-top:4px}

    /* SECTION CARD */
    .section-card{background:var(--surface);border-radius:var(--r);padding:16px;border:1px solid var(--border);margin-bottom:14px}
    .section-title{font-size:.8rem;font-weight:700;margin-bottom:12px;color:var(--text)}

    /* DROP ZONE */
    .drop-zone{border:2px dashed var(--border-light);border-radius:var(--r-sm);padding:20px 16px;text-align:center;transition:all .3s;cursor:pointer;position:relative}
    .drop-zone.dragging{border-color:var(--primary);background:var(--primary-glow)}
    .drop-zone input[type="file"]{position:absolute;inset:0;opacity:0;cursor:pointer;width:100%}
    .drop-icon{font-size:1.6rem;margin-bottom:6px}
    .drop-text{font-size:.78rem;color:var(--text-dim)}
    .drop-text strong{color:var(--primary)}
    .format-note{font-size:.65rem;color:var(--text-muted);margin-top:6px}
    .action-btn{width:100%;padding:11px;border:none;border-radius:var(--r-sm);font-weight:700;font-size:.85rem;cursor:pointer;transition:all .25s;margin-top:10px}
    .action-btn:hover{transform:translateY(-1px)}
    .action-btn.primary{background:linear-gradient(135deg,var(--primary),#6366f1);color:white;box-shadow:0 4px 14px rgba(59,130,246,.25)}
    .action-btn.green{background:linear-gradient(135deg,var(--success),#16a34a);color:white;box-shadow:0 4px 14px rgba(34,197,94,.2)}
    .text-input{width:100%;background:rgba(15,23,42,.5);border:1.5px solid var(--border);border-radius:var(--r-sm);padding:12px;color:var(--text);font-family:inherit;resize:vertical;min-height:80px;outline:none;font-size:.82rem;transition:.25s}
    .text-input:focus{border-color:var(--primary);box-shadow:0 0 0 3px var(--primary-glow)}

    /* FILE CARDS */
    .file-card{background:var(--surface);border-radius:var(--r-sm);padding:12px;border:1px solid var(--border);transition:border-color .2s}
    .file-card:hover{border-color:var(--border-light)}
    .file-top{display:flex;align-items:center;gap:10px}
    .icon-box{min-width:38px;height:38px;background:var(--surface-2);border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:1.1rem;flex-shrink:0}
    .file-meta{flex:1;overflow:hidden}
    .file-name{font-size:.82rem;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
    .file-details{font-size:.66rem;color:var(--text-dim);margin-top:3px;display:flex;gap:8px;flex-wrap:wrap}
    .file-preview{margin-top:10px;border-radius:8px;overflow:hidden}
    .file-preview img{max-width:100%;height:auto;display:block;margin:0 auto}

    /* TXT PREVIEW */
    .txt-preview{margin-top:10px;background:rgba(15,23,42,.6);border:1px solid var(--border);border-radius:8px;overflow:hidden}
    .txt-content{font-family:'Courier New',monospace;font-size:.72rem;color:#94a3b8;padding:10px 12px;white-space:pre-wrap;word-break:break-all;line-height:1.5;max-height:90px;overflow:hidden;display:block}
    .txt-copy-btn{width:100%;padding:6px;background:rgba(59,130,246,.08);border:none;border-top:1px solid var(--border);color:var(--primary);font-size:.72rem;font-weight:700;cursor:pointer;transition:background .2s}
    .txt-copy-btn:hover{background:rgba(59,130,246,.15)}

    /* FILE ACTIONS */
    .file-actions{display:flex;gap:6px;margin-top:10px;flex-wrap:wrap}
    .btn-sm{flex:1;text-align:center;padding:8px 6px;border-radius:8px;text-decoration:none;font-size:.72rem;font-weight:700;transition:all .2s;border:none;cursor:pointer;display:inline-block;min-width:58px}
    .btn-dl{background:rgba(34,197,94,.1);color:var(--success)}.btn-dl:hover{background:rgba(34,197,94,.2)}
    .btn-info{background:rgba(139,92,246,.1);color:#a78bfa}.btn-info:hover{background:rgba(139,92,246,.2)}
    .btn-rename{background:rgba(59,130,246,.1);color:var(--primary)}.btn-rename:hover{background:rgba(59,130,246,.2)}
    .btn-del{background:rgba(239,68,68,.1);color:var(--danger)}.btn-del:hover{background:rgba(239,68,68,.2)}
    .btn-raw{background:rgba(168,85,247,.12);color:#d8b4fe;border:1px solid rgba(168,85,247,.25);padding:6px 10px;border-radius:8px;font-size:.8rem;cursor:pointer;font-family:inherit;transition:background .15s}
    .btn-raw:hover{background:rgba(168,85,247,.25)}
    .btn-raw:disabled{opacity:.5;cursor:wait}
    .locked-badge{font-size:.7rem;color:var(--text-dim);width:100%;text-align:center;padding:8px;background:rgba(255,255,255,.02);border-radius:8px;border:1px solid var(--border)}

    /* EMPTY STATE */
    .empty-state{text-align:center;padding:40px 20px;color:var(--text-dim);background:var(--surface);border:1px solid var(--border);border-radius:var(--r);transition:background .3s ease,backdrop-filter .3s ease,border-color .3s ease}
    .empty-state .icon{font-size:2rem;margin-bottom:10px;opacity:.5}
    .empty-state p{font-size:.82rem}

    /* MODALS */
    .modal-overlay{display:none;position:fixed;inset:0;z-index:2000;background:rgba(0,0,0,.65);backdrop-filter:blur(4px);align-items:center;justify-content:center}
    .modal-overlay.active{display:flex}
    .modal-box{background:var(--surface);border-radius:var(--r);padding:24px;width:92%;max-width:360px;border:1px solid var(--border)}
    .modal-box h3{font-size:.92rem;margin-bottom:14px}
    .modal-box input{width:100%;background:var(--bg);border:1.5px solid var(--border);padding:11px 14px;border-radius:var(--r-sm);color:var(--text);outline:none;font-size:.86rem;margin-bottom:12px}
    .modal-box input:focus{border-color:var(--primary)}
    .modal-actions{display:flex;gap:8px}
    .modal-actions button{flex:1;padding:11px;border-radius:var(--r-sm);font-weight:700;cursor:pointer;border:none;font-size:.84rem}
    .modal-actions .cancel{background:var(--border);color:var(--text)}
    .modal-actions .confirm{background:var(--primary);color:white}

    /* TOAST */
    .toast{position:fixed;top:72px;left:50%;transform:translateX(-50%) translateY(-16px);background:var(--surface-2);border:1px solid var(--border);border-radius:12px;padding:12px 20px;z-index:3000;font-size:.82rem;font-weight:600;box-shadow:0 12px 40px rgba(0,0,0,.4);opacity:0;pointer-events:none;transition:all .4s cubic-bezier(.16,1,.3,1);display:flex;align-items:center;gap:8px;max-width:88%}
    .toast.show{opacity:1;transform:translateX(-50%) translateY(0)}

    /* VIEW USER BANNER */
    .view-banner{background:rgba(245,158,11,.08);border:1px solid rgba(245,158,11,.2);border-radius:10px;padding:10px 14px;margin-bottom:12px;font-size:.78rem;color:#fbbf24}

    /* SEARCH RESULTS */
    .search-info{font-size:.74rem;color:var(--text-dim);margin-bottom:10px}

    /* TABS */
    .tab-bar{display:flex;gap:4px;margin-bottom:14px;background:var(--surface);border-radius:12px;padding:4px;border:1px solid var(--border)}
    .tab-btn{flex:1;padding:10px 16px;border:none;border-radius:10px;font-size:.82rem;font-weight:700;cursor:pointer;transition:all .25s;text-decoration:none;text-align:center;color:var(--text-dim);background:transparent}
    .tab-btn:hover{color:var(--text);background:rgba(255,255,255,.03)}
    .tab-btn.active{background:linear-gradient(135deg,var(--primary),#6366f1);color:white;box-shadow:0 2px 10px rgba(59,130,246,.3)}

    /* FOLDER TABS */
    .folder-tab-bar{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px;padding:6px;background:var(--surface);border-radius:12px;border:1px solid var(--border)}
    .folder-tab{display:inline-flex;align-items:center;gap:6px;padding:7px 12px;border-radius:9px;font-size:.76rem;font-weight:700;text-decoration:none;color:var(--text-dim);background:transparent;border:1px solid transparent;cursor:pointer;font-family:inherit;transition:all .2s;white-space:nowrap}
    .folder-tab:hover{background:rgba(255,255,255,.04);color:var(--text)}
    .folder-tab.active{background:var(--primary-glow);border-color:rgba(59,130,246,.3);color:var(--primary)}
    .folder-count{display:inline-flex;align-items:center;justify-content:center;min-width:18px;height:18px;padding:0 5px;font-size:.62rem;font-weight:800;background:rgba(255,255,255,.06);border-radius:9px;color:var(--text-dim)}
    .folder-tab.active .folder-count{background:rgba(59,130,246,.2);color:var(--primary)}
    .folder-tab-group{display:inline-flex;align-items:center;gap:3px;border-radius:9px;padding:1px;border:1px solid transparent}
    .folder-tab-group.active{border-color:rgba(59,130,246,.18);background:rgba(59,130,246,.05)}
    .folder-tab-actions{display:inline-flex;gap:3px;margin-right:4px}
    .folder-tab-mini{background:rgba(255,255,255,.06);border:none;color:var(--text);width:22px;height:22px;border-radius:6px;font-size:.66rem;cursor:pointer;display:inline-flex;align-items:center;justify-content:center;text-decoration:none;line-height:1}
    .folder-tab-mini:hover{background:rgba(255,255,255,.12)}
    .folder-tab-mini.danger{background:rgba(239,68,68,.12);color:var(--danger)}
    .folder-tab-mini.danger:hover{background:rgba(239,68,68,.22)}
    .folder-tab-add{background:rgba(59,130,246,.08);color:var(--primary);border:1px dashed rgba(59,130,246,.3)}
    .folder-tab-add:hover{background:rgba(59,130,246,.15);color:var(--primary)}
    .folder-tab-limit{color:var(--text-muted);cursor:default;border:1px dashed var(--border)}

    /* CAPTIONS */
    .file-caption{font-size:.74rem;color:var(--text);margin-top:8px;padding:7px 10px;background:rgba(15,23,42,.6);border:1px solid var(--border);border-radius:8px;line-height:1.55;word-break:break-word}
    .file-caption-empty{font-size:.7rem;color:var(--text-muted);margin-top:6px;font-style:italic}
    .file-preview-gif{margin-top:10px;border-radius:8px;overflow:hidden;background:#000;display:flex;align-items:center;justify-content:center}
    .file-preview-gif img{max-width:100%;height:auto;display:block;background:#000}
    .gif-badge{position:absolute;top:6px;right:6px;background:rgba(139,92,246,.85);color:#fff;font-size:.6rem;font-weight:800;padding:2px 6px;border-radius:6px;letter-spacing:.5px}
    .file-preview-wrap{position:relative}

    /* MOVE SUBMENU */
    .move-submenu{margin-top:4px;padding-top:6px;border-top:1px solid var(--border)}
    .move-submenu .submenu-label{font-size:.66rem;color:var(--text-muted);padding:4px 12px 6px}

    /* THREE DOT MENU */
    .file-top{position:relative}
    .three-dot-btn{background:none;border:none;color:var(--text-dim);cursor:pointer;padding:4px 6px;border-radius:6px;font-size:1.1rem;line-height:1;transition:all .2s;flex-shrink:0}
    .three-dot-btn:hover{background:rgba(255,255,255,.08);color:var(--text)}
    .dot-menu{display:none;position:absolute;top:100%;left:0;background:var(--surface-2);border:1px solid var(--border);border-radius:10px;padding:6px;z-index:100;min-width:160px;box-shadow:0 8px 24px rgba(0,0,0,.4)}
    .dot-menu.show{display:block}
    .dot-menu-item{display:flex;align-items:center;gap:8px;padding:8px 12px;font-size:.76rem;color:var(--text);border-radius:8px;cursor:pointer;transition:background .15s;border:none;background:none;width:100%;text-align:right;font-family:inherit}
    .dot-menu-item:hover{background:rgba(255,255,255,.06)}
    .dot-menu-item.danger{color:var(--danger)}
    .dot-menu-item.danger:hover{background:rgba(239,68,68,.1)}

    /* SHARE MODAL */
    .share-user-list{max-height:220px;overflow-y:auto;margin:10px 0}
    .share-user-item{display:flex;align-items:center;gap:8px;padding:8px 10px;border-radius:8px;transition:background .15s;cursor:pointer}
    .share-user-item:hover{background:rgba(255,255,255,.04)}
    .share-user-item input[type="checkbox"]{accent-color:var(--primary);width:16px;height:16px}
    .share-user-item label{font-size:.8rem;cursor:pointer;flex:1}

    /* SHARED FILES SECTION */
    .shared-section{margin-top:16px;padding-top:16px;border-top:1px solid var(--border)}
    .shared-badge{display:inline-flex;align-items:center;gap:4px;padding:2px 8px;border-radius:12px;font-size:.64rem;font-weight:600;background:rgba(245,158,11,.1);color:#fbbf24;border:1px solid rgba(245,158,11,.15)}

    /* USERNAME ON MOBILE */
    .mobile-username{display:none;font-size:.72rem;font-weight:700;color:var(--primary);margin-right:auto}

    @keyframes spin{to{transform:rotate(360deg)}}

    /* BG PICKER MODAL */
    .bg-pick-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:8px;max-height:60vh;overflow-y:auto;padding:2px}
    @media(max-width:399px){.bg-pick-grid{grid-template-columns:repeat(2,1fr)}}
    .bg-pick-item{background:none;border:2px solid transparent;padding:5px;border-radius:10px;cursor:pointer;font-family:inherit;color:var(--text);transition:border-color .2s,background .2s,transform .15s;display:flex;flex-direction:column;gap:6px}
    @media (hover:hover) and (pointer:fine){.bg-pick-item:hover{background:rgba(255,255,255,.04);border-color:var(--border-light)}}
    .bg-pick-item:active{transform:scale(.97);transition-duration:.08s}
    .bg-pick-item.active{border-color:var(--primary);background:var(--primary-glow)}
    .bg-pick-item.active .bg-pick-label{color:var(--primary)}
    .bg-pick-thumb{width:100%;aspect-ratio:16/10;object-fit:cover;border-radius:7px;display:block;background:#1a2235}
    .bg-pick-default{background:linear-gradient(135deg,#0a0e1a,#111827);display:flex;align-items:center;justify-content:center;font-size:1.5rem;color:var(--primary)}
    .bg-pick-label{font-size:.7rem;font-weight:600;text-align:center;color:var(--text-dim);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;line-height:1.4}

    @media(max-width:420px){
        .nav-btn .btn-text{display:none}
        .header-actions{gap:3px}
        .nav-btn{padding:5px 7px}
        .mobile-username{display:block}
    }
