    <script>
    function openPkModal(){document.getElementById('pkModal').classList.add('active');pkLoadList();}
    function closePkModal(){document.getElementById('pkModal').classList.remove('active');}
    document.getElementById('pkModal').addEventListener('click',function(e){if(e.target===this)closePkModal();});
    function pb64d(s){s=s.replace(/-/g,'+').replace(/_/g,'/');while(s.length%4)s+='=';const b=atob(s),a=new Uint8Array(b.length);for(let i=0;i<b.length;i++)a[i]=b.charCodeAt(i);return a.buffer;}
    function pb64e(buf){const a=new Uint8Array(buf instanceof ArrayBuffer?buf:buf);return btoa(String.fromCharCode(...a)).replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');}
    async function pkLoadList(){
        const el=document.getElementById('pkList');
        try{
            const d=await(await fetch('?action=passkey_list')).json();
            if(!d.items||!d.items.length){el.innerHTML='<div style="color:#475569;text-align:center;padding:10px">هنوز Passkey ثبت نشده</div>';return;}
            el.innerHTML=d.items.map(p=>`
                <div style="display:flex;align-items:center;justify-content:space-between;padding:9px 10px;
                    background:#0a0e1a;border-radius:9px;border:1px solid #1e293b;margin-bottom:6px">
                    <div><div style="font-weight:700;font-size:.82rem">${p.name}</div>
                    <div style="font-size:.68rem;color:#475569;margin-top:2px">${p.created}</div></div>
                    <button onclick="pkDelete(${p.id})" style="padding:5px 10px;border:none;border-radius:7px;
                        background:rgba(239,68,68,.1);color:#f87171;font-size:.72rem;cursor:pointer;font-weight:700">حذف</button>
                </div>`).join('');
        }catch(e){el.innerHTML='<div style="color:#f87171">خطا در بارگذاری</div>';}
    }
    async function pkDelete(id){
        if(!confirm('این Passkey حذف شود؟'))return;
        const fd=new FormData();fd.append('id',id);
        await fetch('?action=passkey_delete',{method:'POST',body:fd});
        pkLoadList();
    }
    async function pkRegister(){
        const st=document.getElementById('pkRegSt'),btn=document.getElementById('pkAddBtn');
        const name=document.getElementById('pkName').value.trim()||'Passkey';
        if(!window.PublicKeyCredential){st.style.color='#f87171';st.textContent='مرورگر پشتیبانی نمی‌کند';return;}
        btn.disabled=true;st.style.color='#94a3b8';st.textContent='در حال آماده‌سازی...';
        try{
            const opts=await(await fetch('?action=passkey_register_challenge')).json();
            opts.challenge=pb64d(opts.challenge);opts.user.id=pb64d(opts.user.id);
            if(opts.excludeCredentials)opts.excludeCredentials=opts.excludeCredentials.map(c=>({...c,id:pb64d(c.id),transports:['internal']}));
            // Force device-only passkey — block Google Password Manager sync
            opts.hints=['client-device'];
            if(!opts.authenticatorSelection)opts.authenticatorSelection={};
            opts.authenticatorSelection.authenticatorAttachment='platform';
            opts.authenticatorSelection.residentKey='required';
            opts.authenticatorSelection.requireResidentKey=true;
            opts.authenticatorSelection.userVerification='required';
            st.textContent='بیومتریک یا PIN دستگاه را تأیید کنید...';
            const cred=await navigator.credentials.create({publicKey:opts});
            const body={name,clientDataJSON:pb64e(cred.response.clientDataJSON),attestationObject:pb64e(cred.response.attestationObject)};
            const res=await(await fetch('?action=passkey_register_verify',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)})).json();
            if(res.ok){st.style.color='#4ade80';st.textContent='✓ Passkey ثبت شد';document.getElementById('pkName').value='';setTimeout(pkLoadList,600);}
            else throw new Error(res.error||'خطا');
        }catch(e){
            st.style.color='#f87171';
            if(e.name==='NotAllowedError')st.textContent='عملیات لغو شد';
            else if(e.name==='InvalidStateError')st.textContent='این دستگاه قبلاً ثبت شده';
            else st.textContent='خطا: '+e.message;
        }finally{btn.disabled=false;}
    }
    </script>

        <!-- Rename Modal -->
