    <div class="toast" id="toast"></div>
    <script>
    (function(){
        const msgs=<?php echo json_encode($msgs);?>;const msg='<?php echo h($msg);?>';
        if(msg&&msgs[msg]){const t=document.getElementById('toast');
            const qp=new URLSearchParams(window.location.search);
            const uploaded=parseInt(qp.get('uploaded')||'0',10);const failed=parseInt(qp.get('failed')||'0',10);
            let label=msgs[msg][1];
            if(msg==='success'&&uploaded>1)label=uploaded+' فایل آپلود شد';
            else if(msg==='partial_success')label=uploaded+' فایل آپلود شد، '+failed+' ناموفق';
            t.innerHTML='<span>'+msgs[msg][0]+'</span><span>'+label+'</span>';
            setTimeout(()=>t.classList.add('show'),80);setTimeout(()=>t.classList.remove('show'),3200);
            var _cleanUrl=window.location.pathname+'?action=dashboard&tab=<?php echo urlencode($activeTab);?>';
            <?php if($viewUser!==$_SESSION['user']):?>_cleanUrl+='&view_user=<?php echo urlencode($viewUser);?>';<?php endif;?>
            history.replaceState(null,'',_cleanUrl);}
    })();

    const dz=document.getElementById('dropZone'),fi=document.getElementById('fileInput'),fl=document.getElementById('fileLabel');
    if(dz){
        const showSelected=files=>{
            if(!files||!files.length)return;
            const first=files[0].name;
            fl.innerHTML=files.length>1
                ?'<strong>'+files.length+' فایل انتخاب شد</strong><br><span style="font-size:.78rem;opacity:.75">'+first+(files.length>1?' و '+(files.length-1)+' فایل دیگر':'')+'</span>'
                :'<strong>'+first+'</strong>';
        };
        ['dragenter','dragover'].forEach(e=>dz.addEventListener(e,ev=>{ev.preventDefault();dz.classList.add('dragging')}));
        ['dragleave','drop'].forEach(e=>dz.addEventListener(e,ev=>{ev.preventDefault();dz.classList.remove('dragging')}));
        dz.addEventListener('drop',e=>{if(e.dataTransfer.files.length){fi.files=e.dataTransfer.files;showSelected(fi.files);}});
        fi.addEventListener('change',()=>showSelected(fi.files));
        document.getElementById('uploadFileForm').addEventListener('submit',function(){
            const btn=document.getElementById('uploadBtn');const n=fi.files?fi.files.length:0;
            btn.disabled=true;btn.style.opacity='.65';btn.textContent=n>1?('در حال آپلود '+n+' فایل...'):'در حال آپلود...';});
    }
    // Raw view: mint one-shot token and open in new tab
    document.addEventListener('click', async function(e){
        var btn = e.target.closest('.btn-raw');
        if (!btn || btn.disabled) return;
        btn.disabled = true;
        var origText = btn.textContent;
        btn.textContent = '⏳ ...';
        try {
            var fd = new FormData();
            fd.append('csrf_token', '<?php echo h($csrf ?? generateCsrfToken()); ?>');
            fd.append('kind', btn.dataset.mintKind);
            if (btn.dataset.mintKind === 'public') {
                fd.append('file_id', btn.dataset.mintFileId);
            } else {
                fd.append('owner', btn.dataset.mintOwner);
                fd.append('name', btn.dataset.mintName);
            }
            var r = await fetch('?action=raw_mint', {
                method: 'POST',
                credentials: 'same-origin',
                body: fd
            });
            var j = await r.json();
            if (j.ok && j.url) {
                window.open(j.url, '_blank', 'noopener,noreferrer');
            } else {
                alert('خطا: ' + (j.error || 'ناشناخته'));
            }
        } catch (err) {
            alert('خطا در ارتباط با سرور');
        } finally {
            btn.disabled = false;
            btn.textContent = origText;
        }
    });

    function openRename(n){document.getElementById('renameOldName').value=n;document.getElementById('renameNewName').value=n;document.getElementById('renameModal').classList.add('active');setTimeout(()=>document.getElementById('renameNewName').focus(),100);}
    function closeRename(){document.getElementById('renameModal').classList.remove('active');}
    document.getElementById('renameModal').addEventListener('click',function(e){if(e.target===this)closeRename();});
    function openPasswordModal(){const m=document.getElementById('passwordModal');if(m){m.classList.add('active');setTimeout(()=>m.querySelector('input').focus(),100);}}
    function closePasswordModal(){const m=document.getElementById('passwordModal');if(m)m.classList.remove('active');}
    (function(){const m=document.getElementById('passwordModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closePasswordModal();});})();
    function copyTxt(btn,text){
        const copy=()=>{btn.textContent='✅ کپی شد!';setTimeout(()=>btn.textContent='📋 کپی پیش‌نمایش',2000);};
        if(navigator.clipboard){navigator.clipboard.writeText(text).then(copy).catch(()=>{fallback(text);copy();});}
        else{fallback(text);copy();}
    }
    function fallback(text){const ta=document.createElement('textarea');ta.value=text;ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta);}

    // Three-dot menu
    function toggleDotMenu(btn){
        // Close all other menus first
        document.querySelectorAll('.dot-menu.show').forEach(m=>{
            if(m!==btn.nextElementSibling)m.classList.remove('show');
        });
        const menu=btn.nextElementSibling;
        menu.classList.toggle('show');
    }
    // Close menus when clicking outside
    document.addEventListener('click',function(e){
        if(!e.target.closest('.three-dot-btn')&&!e.target.closest('.dot-menu')){
            document.querySelectorAll('.dot-menu.show').forEach(m=>m.classList.remove('show'));
        }
    });

    // Helper: toggle all checkboxes inside a list container
    function toggleAllCheckboxes(listId,checked){
        document.querySelectorAll('#'+listId+' input[type="checkbox"]').forEach(cb=>{cb.checked=!!checked;});
    }

    // Share Modal
    function openShareModal(filename,owner){
        const m=document.getElementById('shareModal');if(!m)return;
        document.querySelectorAll('.dot-menu.show').forEach(x=>x.classList.remove('show'));
        document.getElementById('shareFileInput').value=filename;
        document.getElementById('shareOwnerInput').value=owner;
        document.getElementById('shareFileName').textContent='فایل: '+filename+' (صاحب: '+owner+')';
        // Uncheck all
        document.querySelectorAll('#shareUserList input[type="checkbox"]').forEach(cb=>{cb.checked=false;});
        const sa=document.getElementById('shareSelectAll');if(sa)sa.checked=false;
        // Load existing shares
        fetch('?action=get_shares&filename='+encodeURIComponent(filename)+'&owner='+encodeURIComponent(owner))
            .then(r=>r.json()).then(data=>{
                const div=document.getElementById('currentShares');
                if(data.shares&&data.shares.length){
                    div.innerHTML='<div style="font-size:.72rem;color:var(--text-dim);margin-bottom:6px">اشتراک‌های فعلی:</div>'+
                        data.shares.map(s=>'<div style="font-size:.72rem;padding:4px 8px;background:rgba(59,130,246,.06);border-radius:6px;margin-bottom:3px;display:flex;justify-content:space-between;align-items:center"><span>'+s.shared_with+'</span><a href="?action=unshare_file&share_id='+s.id+'" style="color:var(--danger);font-size:.68rem" onclick="return confirm(\'حذف اشتراک؟\')">حذف</a></div>').join('');
                    // Pre-check already shared users
                    data.shares.forEach(s=>{
                        const cb=document.getElementById('share_'+s.shared_with);
                        if(cb)cb.checked=true;
                    });
                }else{div.innerHTML='';}
            }).catch(()=>{});
        m.classList.add('active');
    }
    function closeShareModal(){const m=document.getElementById('shareModal');if(m)m.classList.remove('active');}
    (function(){const m=document.getElementById('shareModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closeShareModal();});})();

    // Public Access Modal
    function openPublicAccessModal(fileId,filename){
        const m=document.getElementById('publicAccessModal');if(!m)return;
        document.querySelectorAll('.dot-menu.show').forEach(x=>x.classList.remove('show'));
        document.getElementById('publicFileIdInput').value=fileId;
        document.getElementById('publicFileName').textContent='فایل: '+filename;
        // Uncheck all
        document.querySelectorAll('#publicUserList input[type="checkbox"]').forEach(cb=>{cb.checked=false;});
        const sa=document.getElementById('publicAccessSelectAll');if(sa)sa.checked=false;
        // Load existing access
        fetch('?action=get_public_access&file_id='+fileId)
            .then(r=>r.json()).then(data=>{
                if(data.users){
                    data.users.forEach(u=>{
                        const cb=document.getElementById('pubaccess_'+u);
                        if(cb)cb.checked=true;
                    });
                }
            }).catch(()=>{});
        m.classList.add('active');
    }
    function closePublicAccessModal(){const m=document.getElementById('publicAccessModal');if(m)m.classList.remove('active');}
    (function(){const m=document.getElementById('publicAccessModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closePublicAccessModal();});})();

    // Public Rename Modal
    function openPublicRenameModal(fileId,filename){
        const m=document.getElementById('publicRenameModal');if(!m)return;
        document.querySelectorAll('.dot-menu.show').forEach(x=>x.classList.remove('show'));
        document.getElementById('publicRenameIdInput').value=fileId;
        document.getElementById('publicRenameNameInput').value=filename;
        m.classList.add('active');
        setTimeout(()=>document.getElementById('publicRenameNameInput').focus(),100);
    }
    function closePublicRenameModal(){const m=document.getElementById('publicRenameModal');if(m)m.classList.remove('active');}
    (function(){const m=document.getElementById('publicRenameModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closePublicRenameModal();});})();

    // Public Caption Modal
    function openPublicCaptionModal(fileId,filename,caption){
        const m=document.getElementById('publicCaptionModal');if(!m)return;
        document.querySelectorAll('.dot-menu.show').forEach(x=>x.classList.remove('show'));
        document.getElementById('publicCaptionIdInput').value=fileId;
        document.getElementById('publicCaptionFileName').textContent='فایل: '+filename;
        document.getElementById('publicCaptionTextInput').value=caption||'';
        m.classList.add('active');
        setTimeout(()=>document.getElementById('publicCaptionTextInput').focus(),100);
    }
    function closePublicCaptionModal(){const m=document.getElementById('publicCaptionModal');if(m)m.classList.remove('active');}
    (function(){const m=document.getElementById('publicCaptionModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closePublicCaptionModal();});})();

    // Folder modals
    function openNewFolder(){
        var m=document.getElementById('newFolderModal');if(!m)return;
        document.getElementById('newFolderName').value='';
        m.classList.add('active');
        setTimeout(function(){document.getElementById('newFolderName').focus();},80);
    }
    function closeNewFolder(){var m=document.getElementById('newFolderModal');if(m)m.classList.remove('active');}
    (function(){var m=document.getElementById('newFolderModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closeNewFolder();});})();

    function openRenameFolder(id,name){
        var m=document.getElementById('renameFolderModal');if(!m)return;
        document.getElementById('renameFolderId').value=id;
        document.getElementById('renameFolderName').value=name;
        m.classList.add('active');
        setTimeout(function(){var i=document.getElementById('renameFolderName');i.focus();i.select();},80);
    }
    function closeRenameFolder(){var m=document.getElementById('renameFolderModal');if(m)m.classList.remove('active');}
    (function(){var m=document.getElementById('renameFolderModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closeRenameFolder();});})();

    // Caption modal
    function openCaptionModal(filename,owner,currentCaption){
        document.querySelectorAll('.dot-menu.show').forEach(function(m){m.classList.remove('show');});
        var m=document.getElementById('captionModal');if(!m)return;
