        document.getElementById('captionFileName').textContent='فایل: '+filename;
        document.getElementById('captionTextInput').value=currentCaption||'';
        m.classList.add('active');
        setTimeout(function(){document.getElementById('captionTextInput').focus();},80);
    }
    function closeCaptionModal(){var m=document.getElementById('captionModal');if(m)m.classList.remove('active');}
    (function(){var m=document.getElementById('captionModal');if(m)m.addEventListener('click',function(e){if(e.target===this)closeCaptionModal();});})();
