<script>
function openBgPicker(){document.getElementById('bgPickerOverlay').classList.add('active');}
function closeBgPicker(){document.getElementById('bgPickerOverlay').classList.remove('active');}
document.addEventListener('keydown',function(e){
    if(e.key==='Escape'){
        var ov=document.getElementById('bgPickerOverlay');
        if(ov&&ov.classList.contains('active'))closeBgPicker();
    }
});

function setBg(id){
    var fd=new FormData();
    fd.append('csrf_token','<?=h($csrf)?>');
    fd.append('bg_id',id);
    fetch('?action=bg_set',{method:'POST',body:fd,credentials:'same-origin'})
        .then(function(r){return r.ok?r.json():Promise.reject(r.status);})
        .then(function(d){
            if(!d.ok)return;
            document.querySelectorAll('.bg-pick-item').forEach(function(b){
                b.classList.toggle('active',parseInt(b.dataset.bgId,10)===id);
            });
            applyBg(id,d.url);
            setTimeout(closeBgPicker,260);
        })
        .catch(function(err){console.warn('bg_set failed',err);});
}

function applyBg(id,url){
    var body=document.body;
    var existing=document.getElementById('user-bg-runtime-style');
    if(!id||id===0||!url){
        body.classList.remove('has-custom-bg');
        if(existing)existing.remove();
        return;
    }
    var s=existing;
    if(!s){
        s=document.createElement('style');
        s.id='user-bg-runtime-style';
        document.head.appendChild(s);
    }
    var img=new Image();
    img.onload=function(){
        s.textContent='body.has-custom-bg{--user-bg-image:url("'+url.replace(/"/g,'%22')+'")}';
        body.classList.add('has-custom-bg');
    };
    img.onerror=function(){console.warn('bg image load failed',url);};
    img.src=url;
}
</script>

    </body></html>
