                        </form>
                        <?php endif; ?>
                        <form method="POST" action="?action=referral_delete" style="margin:0" onsubmit="return confirm('حذف دائم کد «<?= h($c['code']) ?>»؟ تاریخچهٔ استفاده هم پاک می‌شود.')">
